  email: string;
  avatar: string;
  role: 'Admin' | 'Editor' | 'Viewer';
}

export interface DocumentVersion {
  id: string;
  versionNumber: number;
  updatedAt: string;
  author: string;
  changeNote: string;
  size: string;
}

export interface Document {
  id: string;
  name: string;
  type: FileType;
  ownerId: string;
  folderId: string | null;
  lastModified: string;
  size: string;
  currentVersion: number;
