    let baseDocs = docs;
    if (activeTab === 'starred') baseDocs = docs.filter(d => d.isStarred && !d.isTrashed);
    else if (activeTab === 'trash') baseDocs = docs.filter(d => d.isTrashed);
    else baseDocs = docs.filter(d => !d.isTrashed);

