  DOCX = 'DOCX',
  XLSX = 'XLSX',
  IMG = 'IMG',
  TXT = 'TXT'
}

export interface User {
  id: string;
  name: string;
  email: string;
  avatar: string;
  role: 'Admin' | 'Editor' | 'Viewer';
}

export interface DocumentVersion {
  id: string;
  versionNumber: number;
  updatedAt: string;
  author: string;
  changeNote: string;
  size: string;
}

export interface Document {
  id: string;
  name: string;
  type: FileType;
  ownerId: string;
  folderId: string | null;
  lastModified: string;
  size: string;
  currentVersion: number;
  versions: DocumentVersion[];
  tags: string[];
  isStarred: boolean;
  isTrashed: boolean;
  contractNumber?: string;
}

export interface Folder {
  id: string;
  name: string;
  parentId: string | null;
  createdAt: string;
}

export interface AuditLog {
  id: string;
  docId: string;
  docName: string;
  action: 'Created' | 'Updated' | 'Deleted' | 'Shared' | 'Downloaded';
  user: string;
  timestamp: string;
}

import React, { useState, useMemo } from 'react';
import { 
  Folder as FolderIcon, 
  File, 
  Search, 
  Plus, 
  Clock, 
  Star, 
  Trash2, 
  LayoutDashboard, 
  Database, 
  Settings,
  PanelLeftClose,
  PanelLeftOpen,
  MoreVertical,
  Share2,
  History,
  X,
  Pencil,
  Check
} from 'lucide-react';
import { MOCK_DOCS, MOCK_FOLDERS, MOCK_USER, MOCK_AUDIT_LOGS, getFileIcon } from './constants';
import { Document, Folder, FileType } from './types';
import FileUploader from './components/FileUploader';
import DocumentDetails from './components/DocumentDetails';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'files' | 'dashboard' | 'starred' | 'trash'>('files');
  const [selectedFolderId, setSelectedFolderId] = useState<string | null>(null);
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedDoc, setSelectedDoc] = useState<Document | null>(null);
  const [docs, setDocs] = useState<Document[]>(MOCK_DOCS);
  const [folders, setFolders] = useState<Folder[]>(MOCK_FOLDERS);
  const [isUploading, setIsUploading] = useState(false);

  // Renaming state
  const [editingFolderId, setEditingFolderId] = useState<string | null>(null);
  const [tempFolderName, setTempFolderName] = useState('');

  const activeFolderName = useMemo(() => {
    if (!selectedFolderId) return null;
    return folders.find(f => f.id === selectedFolderId)?.name;
  }, [selectedFolderId, folders]);

  const filteredDocs = useMemo(() => {
    let baseDocs = docs;

    if (activeTab === 'starred') {
      baseDocs = docs.filter(d => d.isStarred && !d.isTrashed);
    } else if (activeTab === 'trash') {
      baseDocs = docs.filter(d => d.isTrashed);
    } else {
      baseDocs = docs.filter(d => !d.isTrashed);
      if (selectedFolderId) {
        baseDocs = baseDocs.filter(d => d.folderId === selectedFolderId);
      }
    }

    if (!searchQuery) return baseDocs;
    return baseDocs.filter(doc => 
      doc.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
      (doc.contractNumber && doc.contractNumber.toLowerCase().includes(searchQuery.toLowerCase())) ||
      doc.tags.some(t => t.toLowerCase().includes(searchQuery.toLowerCase()))
    );
  }, [docs, activeTab, searchQuery, selectedFolderId]);

  const toggleStar = (id: string) => {
    setDocs(prev => prev.map(d => d.id === id ? { ...d, isStarred: !d.isStarred } : d));
  };

  const moveToTrash = (id: string) => {
    setDocs(prev => prev.map(d => d.id === id ? { ...d, isTrashed: true } : d));
    setSelectedDoc(null);
  };

  const handleRenameDoc = (id: string, newName: string) => {
    setDocs(prev => prev.map(d => d.id === id ? { ...d, name: newName } : d));
    if (selectedDoc?.id === id) {
      setSelectedDoc(prev => prev ? { ...prev, name: newName } : null);
    }
  };

  const handleRenameFolder = (id: string, newName: string) => {
    setFolders(prev => prev.map(f => f.id === id ? { ...f, name: newName } : f));
    setEditingFolderId(null);
  };

  const handleUpload = (newFiles: File[], folderId: string | null, metadata: { name: string, contractNumber: string }) => {
    const newDocs: Document[] = newFiles.map((f, i) => ({
      id: `new-${Date.now()}-${i}`,
      name: metadata.name || f.name,
      contractNumber: metadata.contractNumber,
      type: f.name.endsWith('.pdf') ? FileType.PDF : FileType.DOCX,
      ownerId: MOCK_USER.id,
      folderId: folderId,
      lastModified: new Date().toISOString(),
      size: `${(f.size / 1024 / 1024).toFixed(1)} MB`,
      currentVersion: 1,
      versions: [{ id: `v1-${Date.now()}`, versionNumber: 1, updatedAt: new Date().toISOString(), author: MOCK_USER.name, changeNote: 'Initial upload', size: `${(f.size / 1024).toFixed(0)} KB` }],
      tags: [],
      isStarred: false,
      isTrashed: false,
    }));
    setDocs(prev => [...newDocs, ...prev]);
    setIsUploading(false);
  };

  const handleTabChange = (tab: typeof activeTab) => {
    setActiveTab(tab);
    setSelectedFolderId(null);
  };

  const handleFolderClick = (id: string) => {
    setActiveTab('files');
    setSelectedFolderId(id);
  };

  const startRenameFolder = (e: React.MouseEvent, folder: Folder) => {
    e.stopPropagation();
    setEditingFolderId(folder.id);
    setTempFolderName(folder.name);
  };

  return (
    <div className="flex h-screen bg-white text-slate-900 overflow-hidden">
      {/* Sidebar */}
      <aside className={`bg-slate-50 border-r border-slate-200 transition-all duration-300 flex flex-col ${sidebarOpen ? 'w-64' : 'w-16'}`}>
        <div className="p-4 flex items-center gap-3 h-16 border-b border-slate-200">
          <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white shrink-0">
            <Database size={20} />
          </div>
          {sidebarOpen && <span className="font-bold text-lg tracking-tight">DocuMind</span>}
        </div>

        <nav className="flex-1 p-2 space-y-1 overflow-y-auto">
          <NavItem 
            icon={<LayoutDashboard size={20} />} 
            label="Dashboard" 
            active={activeTab === 'dashboard'} 
            collapsed={!sidebarOpen}
            onClick={() => handleTabChange('dashboard')} 
          />
          <NavItem 
            icon={<File size={20} />} 
            label="All Documents" 
            active={activeTab === 'files' && !selectedFolderId} 
            collapsed={!sidebarOpen}
            onClick={() => handleTabChange('files')} 
          />
          <NavItem 
            icon={<Star size={20} />} 
            label="Starred" 
            active={activeTab === 'starred'} 
            collapsed={!sidebarOpen}
            onClick={() => handleTabChange('starred')} 
          />
          <NavItem 
            icon={<Trash2 size={20} />} 
            label="Trash" 
            active={activeTab === 'trash'} 
            collapsed={!sidebarOpen}
            onClick={() => handleTabChange('trash')} 
          />

          <div className="pt-4 pb-2">
             {sidebarOpen && <p className="px-4 text-xs font-semibold text-slate-400 uppercase tracking-wider mb-2">Kebeles</p>}
             {sidebarOpen && folders.map(f => (
               <div key={f.id} className="relative group">
                 {editingFolderId === f.id ? (
                    <div className="flex items-center gap-2 px-2 py-1">
                      <input 
                        autoFocus
                        type="text"
                        value={tempFolderName}
                        onChange={(e) => setTempFolderName(e.target.value)}
                        onKeyDown={(e) => e.key === 'Enter' && handleRenameFolder(f.id, tempFolderName)}
                        onBlur={() => handleRenameFolder(f.id, tempFolderName)}
                        className="w-full text-sm bg-white border border-blue-400 rounded px-2 py-1 outline-none"
                      />
                      <button onClick={() => handleRenameFolder(f.id, tempFolderName)} className="text-green-600 p-1">
                        <Check size={14} />
                      </button>
                    </div>
                 ) : (
                   <button 
                    onClick={() => handleFolderClick(f.id)}
                    className={`w-full flex items-center gap-3 px-4 py-2 text-sm rounded-lg transition-colors ${selectedFolderId === f.id ? 'bg-blue-50 text-blue-600 font-semibold' : 'text-slate-600 hover:bg-slate-200'}`}
                   >
                     <FolderIcon size={16} className={selectedFolderId === f.id ? 'text-blue-500' : 'text-slate-400'} />
                     <span className="flex-1 text-left truncate">{f.name}</span>
                     <Pencil 
                        size={12} 
                        className="opacity-0 group-hover:opacity-100 text-slate-400 hover:text-blue-600 transition-opacity" 
                        onClick={(e) => startRenameFolder(e, f)}
                      />
                   </button>
                 )}
               </div>
             ))}
             {!sidebarOpen && <div className="flex justify-center py-2"><FolderIcon size={20} className="text-slate-400" /></div>}
          </div>
        </nav>

        <div className="p-4 border-t border-slate-200">
          <div className="flex items-center gap-3">
            <img src={MOCK_USER.avatar} alt="User" className="w-8 h-8 rounded-full border border-slate-200" />
            {sidebarOpen && (
              <div className="flex-1 overflow-hidden">
                <p className="text-sm font-medium truncate">{MOCK_USER.name}</p>
                <p className="text-xs text-slate-500 truncate">{MOCK_USER.role}</p>
              </div>
            )}
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col min-w-0 bg-white">
        {/* Top Header */}
        <header className="h-16 border-b border-slate-200 flex items-center justify-between px-6 shrink-0">
          <div className="flex items-center gap-4 flex-1">
            <button onClick={() => setSidebarOpen(!sidebarOpen)} className="p-2 hover:bg-slate-100 rounded-lg text-slate-500">
              {sidebarOpen ? <PanelLeftClose size={20} /> : <PanelLeftOpen size={20} />}
            </button>
            <div className="relative max-w-md w-full">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                type="text" 
                placeholder="Search documents, contract #, tags..." 
                className="w-full pl-10 pr-4 py-2 bg-slate-100 border-none rounded-full text-sm focus:ring-2 focus:ring-blue-500 focus:bg-white transition-all outline-none"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
            </div>
          </div>
          <div className="flex items-center gap-3">
            <button 
              onClick={() => setIsUploading(true)}
              className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors shadow-sm"
            >
              <Plus size={18} />
              <span>Upload</span>
            </button>
            <button className="p-2 hover:bg-slate-100 rounded-lg text-slate-500">
              <Settings size={20} />
            </button>
          </div>
        </header>

        {/* Content Area */}
        <div className="flex-1 overflow-y-auto p-6">
          {activeTab === 'files' || activeTab === 'starred' || activeTab === 'trash' ? (
            <div className="space-y-6">
              <div className="flex items-center justify-between">
                <div>
                  <h1 className="text-2xl font-bold text-slate-900 capitalize">
                    {selectedFolderId ? activeFolderName : activeTab}
                  </h1>
                  {selectedFolderId && <p className="text-sm text-slate-500 mt-1">Viewing records for this administrative unit</p>}
                </div>
                <div className="flex items-center gap-2 text-sm text-slate-500">
                  <Clock size={16} />
                  <span>Last synced: Just now</span>
                </div>
              </div>

              {/* Document List Table */}
              <div className="bg-white border border-slate-200 rounded-xl overflow-hidden shadow-sm">
                <table className="w-full text-left text-sm border-collapse">
                  <thead className="bg-slate-50 border-b border-slate-200 text-slate-500 font-medium">
                    <tr>
                      <th className="px-6 py-4">Name</th>
                      <th className="px-6 py-4">Contract #</th>
                      <th className="px-6 py-4">Last Modified</th>
                      <th className="px-6 py-4">Size</th>
                      <th className="px-6 py-4 text-right">Actions</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    {filteredDocs.length > 0 ? filteredDocs.map(doc => (
                      <tr 
                        key={doc.id} 
                        className={`hover:bg-blue-50/50 cursor-pointer transition-colors ${selectedDoc?.id === doc.id ? 'bg-blue-50' : ''}`}
                        onClick={() => setSelectedDoc(doc)}
                      >
                        <td className="px-6 py-4">
                          <div className="flex items-center gap-3">
                            <div className="shrink-0 p-2 bg-slate-100 rounded-lg">
                              {getFileIcon(doc.type)}
                            </div>
                            <div className="flex flex-col">
                              <span className="font-semibold text-slate-800">{doc.name}</span>
                              <div className="flex items-center gap-1 mt-0.5">
                                {doc.tags.map(tag => (
                                  <span key={tag} className="px-1.5 py-0.5 bg-slate-100 text-slate-500 rounded text-[10px] font-medium uppercase">{tag}</span>
                                ))}
                              </div>
                            </div>
                          </div>
                        </td>
                        <td className="px-6 py-4 text-slate-600 font-medium">
                          {doc.contractNumber || '-'}
                        </td>
                        <td className="px-6 py-4 text-slate-500">
                          {new Date(doc.lastModified).toLocaleDateString()}
                        </td>
                        <td className="px-6 py-4 text-slate-500 font-medium">{doc.size}</td>
                        <td className="px-6 py-4 text-right">
                          <div className="flex items-center justify-end gap-1">
                            <button 
                              onClick={(e) => { e.stopPropagation(); toggleStar(doc.id); }} 
                              className={`p-2 rounded-lg hover:bg-slate-100 ${doc.isStarred ? 'text-amber-400' : 'text-slate-400'}`}
                            >
                              <Star size={18} fill={doc.isStarred ? "currentColor" : "none"} />
                            </button>
                            <button className="p-2 rounded-lg hover:bg-slate-100 text-slate-400">
                              <Share2 size={18} />
                            </button>
                            <button className="p-2 rounded-lg hover:bg-slate-100 text-slate-400">
                              <MoreVertical size={18} />
                            </button>
                          </div>
                        </td>
                      </tr>
                    )) : (
                      <tr>
                        <td colSpan={5} className="px-6 py-12 text-center text-slate-400">
                          <div className="flex flex-col items-center gap-2">
                            <File size={48} className="text-slate-200" />
                            <p>No documents found</p>
                            {selectedFolderId && (
                                <button 
                                    onClick={() => setIsUploading(true)}
                                    className="mt-2 text-blue-600 font-semibold hover:underline"
                                >
                                    Upload the first document to {activeFolderName}
                                </button>
                            )}
                          </div>
                        </td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="md:col-span-2 space-y-6">
                <div className="bg-gradient-to-br from-blue-600 to-indigo-700 rounded-2xl p-8 text-white">
                  <h2 className="text-3xl font-bold mb-2">Welcome back, {MOCK_USER.name}</h2>
                  <p className="text-blue-100 opacity-90 mb-6">Manage records across {folders.length} kebeles efficiently.</p>
                  <button onClick={() => setActiveTab('files')} className="bg-white text-blue-600 px-6 py-2 rounded-full font-semibold text-sm hover:bg-blue-50 transition-colors">
                    View Recent Files
                  </button>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <StatCard label="Total Documents" value={docs.length} icon={<File className="text-blue-600" />} />
                  <StatCard label="Storage Used" value="4.2 GB / 10 GB" icon={<Database className="text-indigo-600" />} />
                </div>

                <div className="bg-white p-6 border border-slate-200 rounded-xl shadow-sm">
                  <h3 className="font-bold mb-4 flex items-center gap-2">
                    <History size={18} className="text-blue-600" />
                    Recent Activity
                  </h3>
                  <div className="space-y-4">
                    {MOCK_AUDIT_LOGS.map(log => (
                      <div key={log.id} className="flex items-start gap-4 p-3 hover:bg-slate-50 rounded-lg transition-colors border-l-2 border-transparent hover:border-blue-500">
                        <div className="p-2 bg-blue-50 rounded-lg shrink-0">
                          <Plus size={16} className="text-blue-600" />
                        </div>
                        <div>
                          <p className="text-sm font-medium text-slate-800">
                            <span className="text-blue-600">{log.user}</span> {log.action.toLowerCase()} <span className="font-semibold">{log.docName}</span>
                          </p>
                          <p className="text-xs text-slate-400 mt-0.5">{new Date(log.timestamp).toLocaleString()}</p>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              </div>

              <div className="space-y-6">
                <div className="bg-slate-900 text-white p-6 rounded-xl shadow-lg">
                  <h3 className="font-bold mb-2">Pro Feature</h3>
                  <p className="text-xs text-slate-400 mb-4">Integrate DocuMind with your Slack or Teams workspace.</p>
                  <button className="w-full py-2 bg-blue-600 hover:bg-blue-500 text-xs font-bold rounded-lg">Explore Integrations</button>
                </div>
              </div>
            </div>
          )}
        </div>
      </main>

      {/* Right Details Panel */}
      {selectedDoc && (
        <aside className="w-96 bg-white border-l border-slate-200 overflow-y-auto flex flex-col shrink-0">
          <div className="h-16 flex items-center justify-between px-6 border-b border-slate-200 sticky top-0 bg-white z-10">
            <h3 className="font-bold">Details</h3>
            <button onClick={() => setSelectedDoc(null)} className="p-2 hover:bg-slate-100 rounded-lg text-slate-500">
              <X size={20} />
            </button>
          </div>
          <DocumentDetails doc={selectedDoc} onRename={handleRenameDoc} onTrash={() => moveToTrash(selectedDoc.id)} />
        </aside>
      )}

      {/* Upload Modal */}
      {isUploading && (
        <FileUploader 
          folders={folders} 
          initialFolderId={selectedFolderId}
          onUpload={handleUpload} 
          onClose={() => setIsUploading(false)} 
        />
      )}
    </div>
  );
};

const NavItem: React.FC<{ icon: React.ReactNode, label: string, active: boolean, onClick: () => void, collapsed: boolean }> = ({ icon, label, active, onClick, collapsed }) => (
  <button 
    onClick={onClick}
    className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm font-medium transition-all ${active ? 'bg-blue-600 text-white shadow-md shadow-blue-200' : 'text-slate-600 hover:bg-slate-100'}`}
    title={collapsed ? label : undefined}
  >
    <div className="shrink-0">{icon}</div>
    {!collapsed && <span>{label}</span>}
  </button>
);

const StatCard: React.FC<{ label: string, value: string | number, icon: React.ReactNode }> = ({ label, value, icon }) => (
  <div className="bg-white p-6 border border-slate-200 rounded-xl shadow-sm">
    <div className="flex items-center justify-between mb-2">
      <p className="text-xs font-semibold text-slate-400 uppercase tracking-wider">{label}</p>
      <div className="p-2 bg-slate-50 rounded-lg">{icon}</div>
    </div>
    <p className="text-2xl font-bold text-slate-900">{value}</p>
  </div>
);

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { Upload, X, File, Folder as FolderIcon, ChevronDown, Tag, Hash } from 'lucide-react';
import { Folder } from '../types';

interface FileUploaderProps {
  folders: Folder[];
  initialFolderId?: string | null;
  onUpload: (files: File[], folderId: string | null, metadata: { name: string, contractNumber: string }) => void;
  onClose: () => void;
}

const FileUploader: React.FC<FileUploaderProps> = ({ folders, initialFolderId, onUpload, onClose }) => {
  const [dragActive, setDragActive] = useState(false);
  const [files, setFiles] = useState<File[]>([]);
  const [selectedFolderId, setSelectedFolderId] = useState<string | null>(initialFolderId || (folders.length > 0 ? folders[0].id : null));
  const [docName, setDocName] = useState('');
  const [contractNumber, setContractNumber] = useState('');
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (initialFolderId !== undefined) {
      setSelectedFolderId(initialFolderId);
    }
  }, [initialFolderId]);

  const handleDrag = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") {
      setDragActive(true);
    } else if (e.type === "dragleave") {
      setDragActive(false);
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      const newFiles = Array.from(e.dataTransfer.files);
      setFiles(prev => [...prev, ...newFiles]);
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const newFiles = Array.from(e.target.files);
      setFiles(prev => [...prev, ...newFiles]);
    }
  };

  const removeFile = (index: number) => {
    setFiles(prev => prev.filter((_, i) => i !== index));
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-sm p-4">
      <div className="bg-white w-full max-w-xl rounded-2xl shadow-2xl overflow-hidden flex flex-col animate-in fade-in zoom-in duration-300">
        <div className="p-6 border-b border-slate-100 flex items-center justify-between">
          <h2 className="text-xl font-bold">Upload Document</h2>
          <button onClick={onClose} className="p-2 hover:bg-slate-100 rounded-lg transition-colors">
            <X size={20} className="text-slate-400" />
          </button>
        </div>

        <div className="p-8 space-y-6 max-h-[70vh] overflow-y-auto">
          {/* Metadata Section */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-400 uppercase tracking-wider flex items-center gap-2">
                <Tag size={14} /> Document Label (Name)
              </label>
              <input 
                type="text" 
                placeholder="e.g. Q4 Strategy"
                value={docName}
                onChange={(e) => setDocName(e.target.value)}
                className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-blue-500 outline-none transition-all"
              />
            </div>
            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-400 uppercase tracking-wider flex items-center gap-2">
                <Hash size={14} /> Contract Number
              </label>
              <input 
                type="text" 
                placeholder="e.g. CN-2024-001"
                value={contractNumber}
                onChange={(e) => setContractNumber(e.target.value)}
                className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-blue-500 outline-none transition-all"
              />
            </div>
          </div>

          {/* Destination Folder Selection */}
          <div className="space-y-2">
            <label className="text-xs font-bold text-slate-400 uppercase tracking-wider flex items-center gap-2">
              <FolderIcon size={14} /> Destination Kebele
            </label>
            <div className="relative">
              <select 
                value={selectedFolderId || ''} 
                onChange={(e) => setSelectedFolderId(e.target.value || null)}
                className="w-full pl-4 pr-10 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm appearance-none focus:ring-2 focus:ring-blue-500 outline-none cursor-pointer transition-all hover:bg-slate-100"
              >
                <option value="">Root / General</option>
                {folders.map(folder => (
                  <option key={folder.id} value={folder.id}>
                    {folder.name}
                  </option>
                ))}
              </select>
              <ChevronDown size={18} className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" />
            </div>
          </div>

          {/* Drag & Drop Area */}
          <div 
            className={`relative border-2 border-dashed rounded-2xl p-10 transition-all flex flex-col items-center justify-center text-center gap-4 ${
              dragActive ? 'border-blue-500 bg-blue-50 scale-[1.01]' : 'border-slate-200 hover:border-slate-300'
            }`}
            onDragEnter={handleDrag}
            onDragLeave={handleDrag}
            onDragOver={handleDrag}
            onDrop={handleDrop}
          >
            <input 
              ref={inputRef}
              type="file" 
              multiple 
              className="absolute inset-0 opacity-0 cursor-pointer"
              onChange={handleFileChange}
            />
            <div className="p-4 bg-blue-50 text-blue-600 rounded-full">
              <Upload size={32} />
            </div>
            <div>
              <p className="text-base font-bold text-slate-800">Drag & drop files here</p>
              <p className="text-xs text-slate-500 mt-1">Or click to browse from your computer</p>
            </div>
          </div>

          {files.length > 0 && (
            <div className="space-y-3">
              <p className="text-xs font-bold text-slate-400 uppercase tracking-wider">Ready to upload ({files.length})</p>
              {files.map((file, i) => (
                <div key={i} className="flex items-center gap-3 p-3 bg-slate-50 rounded-xl border border-slate-100 group">
                  <div className="p-2 bg-white rounded-lg border border-slate-200 shadow-sm">
                    <File size={16} className="text-blue-500" />
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-semibold truncate">{file.name}</p>
                    <p className="text-xs text-slate-400">{(file.size / 1024).toFixed(1)} KB</p>
                  </div>
                  <button onClick={() => removeFile(i)} className="p-2 text-slate-300 hover:text-red-500 transition-colors">
                    <X size={16} />
                  </button>
                </div>
              ))}
            </div>
          )}
        </div>

        <div className="p-6 bg-slate-50 border-t border-slate-100 flex gap-3 mt-auto">
          <button 
            onClick={onClose}
            className="flex-1 px-4 py-3 bg-white border border-slate-200 rounded-xl text-sm font-bold text-slate-600 hover:bg-slate-50 transition-colors shadow-sm"
          >
            Cancel
          </button>
          <button 
            onClick={() => onUpload(files, selectedFolderId, { name: docName, contractNumber })}
            disabled={files.length === 0}
            className="flex-1 px-4 py-3 bg-blue-600 text-white rounded-xl text-sm font-bold hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed transition-all shadow-md shadow-blue-200"
          >
            Start Upload
          </button>
        </div>
      </div>
    </div>
  );
};

export default FileUploader;

import React, { useState, useEffect } from 'react';
import { Document } from '../types';
import { getFileIcon } from '../constants';
import { Download, History, Share2, Trash2, Info, User, Calendar, Database, Shield, Pencil, Check, X as CloseIcon, Hash } from 'lucide-react';

interface Props {
  doc: Document;
  onRename: (id: string, newName: string) => void;
  onTrash: () => void;
}

const DocumentDetails: React.FC<Props> = ({ doc, onRename, onTrash }) => {
  const [isRenaming, setIsRenaming] = useState(false);
  const [tempName, setTempName] = useState(doc.name);

  useEffect(() => {
    setTempName(doc.name);
    setIsRenaming(false);
  }, [doc.id]);

  const handleConfirmRename = () => {
    if (tempName.trim() && tempName !== doc.name) {
      onRename(doc.id, tempName);
    }
    setIsRenaming(false);
  };

  return (
    <div className="flex flex-col h-full">
      {/* Overview */}
      <div className="p-6 text-center space-y-4 border-b border-slate-100">
        <div className="inline-flex p-4 bg-slate-50 rounded-2xl border border-slate-100 shadow-sm mx-auto">
          {getFileIcon(doc.type)}
        </div>

        <div className="space-y-1">
          {isRenaming ? (
            <div className="flex items-center gap-2 px-4">
              <input 
                autoFocus
                type="text" 
                className="w-full text-center text-sm font-bold border-b-2 border-blue-500 outline-none pb-1"
                value={tempName}
                onChange={(e) => setTempName(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleConfirmRename()}
              />
              <button onClick={handleConfirmRename} className="p-1 text-green-600 hover:bg-green-50 rounded">
                <Check size={16} />
              </button>
              <button onClick={() => { setIsRenaming(false); setTempName(doc.name); }} className="p-1 text-red-600 hover:bg-red-50 rounded">
                <CloseIcon size={16} />
              </button>
            </div>
          ) : (
            <div className="flex items-center justify-center gap-2 group">
              <h2 className="text-lg font-bold text-slate-900 break-words line-clamp-2">{doc.name}</h2>
              <button 
                onClick={() => setIsRenaming(true)}
                className="opacity-0 group-hover:opacity-100 p-1 text-slate-400 hover:text-blue-600 transition-all"
              >
                <Pencil size={14} />
              </button>
            </div>
          )}
          {doc.contractNumber && (
            <p className="text-xs font-bold text-blue-600 flex items-center justify-center gap-1">
              <Hash size={12} /> {doc.contractNumber}
            </p>
          )}
          <p className="text-sm text-slate-500 mt-1 uppercase tracking-wider font-semibold">Version {doc.currentVersion}</p>
        </div>

        <div className="flex items-center justify-center gap-2 pt-2">
          <ActionButton icon={<Download size={18} />} label="Download" />
          <ActionButton icon={<Share2 size={18} />} label="Share" />
          <ActionButton icon={<Trash2 size={18} />} label="Delete" variant="danger" onClick={onTrash} />
        </div>
      </div>

      {/* Info Sections */}
      <div className="flex-1 overflow-y-auto p-6 space-y-8">
        <section className="space-y-4">
          <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
            <Info size={14} /> Details
          </h3>
          <div className="grid grid-cols-2 gap-4">
            <InfoItem icon={<User size={14} />} label="Owner" value="Alex Rivera" />
            <InfoItem icon={<Database size={14} />} label="Size" value={doc.size} />
            <InfoItem icon={<Calendar size={14} />} label="Created" value="Oct 12, 2023" />
            <InfoItem icon={<Shield size={14} />} label="Security" value="Encrypted" />
          </div>
        </section>

        <section className="space-y-4">
          <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
            <History size={14} /> Version History
          </h3>
          <div className="space-y-3">
            {doc.versions.map((v, idx) => (
              <div key={v.id} className={`p-3 rounded-xl border ${idx === 0 ? 'bg-blue-50 border-blue-100' : 'bg-white border-slate-100 hover:bg-slate-50'} transition-all group`}>
                <div className="flex items-center justify-between mb-1">
                  <span className="text-xs font-bold text-slate-800">v{v.versionNumber}</span>
                  <span className="text-[10px] text-slate-400 font-medium">{new Date(v.updatedAt).toLocaleDateString()}</span>
                </div>
                <p className="text-xs text-slate-600 line-clamp-1">{v.changeNote}</p>
                <div className="mt-2 flex items-center justify-between opacity-0 group-hover:opacity-100 transition-opacity">
                   <span className="text-[10px] text-slate-500 font-medium">By {v.author}</span>
                   <button className="text-[10px] font-bold text-blue-600 hover:underline">Restore</button>
                </div>
              </div>
            ))}
          </div>
        </section>

        <section className="space-y-4 pb-8">
           <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest">Tags</h3>
           <div className="flex flex-wrap gap-2">
              {doc.tags.map(tag => (
                <span key={tag} className="px-2 py-1 bg-slate-100 text-slate-600 rounded-lg text-xs font-medium border border-slate-200">#{tag}</span>
              ))}
              <button className="px-2 py-1 bg-white border border-dashed border-slate-300 text-slate-400 rounded-lg text-xs font-medium hover:border-blue-400 hover:text-blue-500 transition-all">+ Add Tag</button>
           </div>
        </section>
      </div>
    </div>
  );
};

const ActionButton = ({ icon, label, variant = 'default', onClick }: { icon: React.ReactNode, label: string, variant?: 'default' | 'danger', onClick?: () => void }) => (
  <button 
    onClick={onClick}
    className={`p-3 rounded-xl transition-all shadow-sm border ${
      variant === 'danger' 
      ? 'bg-red-50 border-red-100 text-red-600 hover:bg-red-100' 
      : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'
    }`}
    title={label}
  >
    {icon}
  </button>
);

const InfoItem = ({ icon, label, value }: { icon: React.ReactNode, label: string, value: string }) => (
  <div className="space-y-1">
    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider flex items-center gap-1">
      {icon} {label}
    </p>
    <p className="text-sm font-semibold text-slate-800">{value}</p>
  </div>
);

export default DocumentDetails;

import React, { useState, useMemo } from 'react';
import { 
  Folder as FolderIcon, 
  File, 
  Search, 
  Plus, 
  Clock, 
  Star, 
  Trash2, 
  LayoutDashboard, 
  Database, 
  Settings,
  PanelLeftClose,
  PanelLeftOpen,
  MoreVertical,
  Share2,
  History,
  X,
  Pencil,
  Check,
  Server
} from 'lucide-react';
import { MOCK_DOCS, MOCK_FOLDERS, MOCK_USER, MOCK_AUDIT_LOGS, getFileIcon } from './constants';
import { Document, Folder, FileType } from './types';
import FileUploader from './components/FileUploader';
import DocumentDetails from './components/DocumentDetails';
import SystemDesign from './components/SystemDesign';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'files' | 'dashboard' | 'starred' | 'trash' | 'system'>('files');
  const [selectedFolderId, setSelectedFolderId] = useState<string | null>(null);
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedDoc, setSelectedDoc] = useState<Document | null>(null);
  const [docs, setDocs] = useState<Document[]>(MOCK_DOCS);
  const [folders, setFolders] = useState<Folder[]>(MOCK_FOLDERS);
  const [isUploading, setIsUploading] = useState(false);

  // Renaming state
  const [editingFolderId, setEditingFolderId] = useState<string | null>(null);
  const [tempFolderName, setTempFolderName] = useState('');

  const activeFolderName = useMemo(() => {
    if (!selectedFolderId) return null;
    return folders.find(f => f.id === selectedFolderId)?.name;
  }, [selectedFolderId, folders]);

  const filteredDocs = useMemo(() => {
    let baseDocs = docs;

    if (activeTab === 'starred') {
      baseDocs = docs.filter(d => d.isStarred && !d.isTrashed);
    } else if (activeTab === 'trash') {
      baseDocs = docs.filter(d => d.isTrashed);
    } else {
      baseDocs = docs.filter(d => !d.isTrashed);
      if (selectedFolderId) {
        baseDocs = baseDocs.filter(d => d.folderId === selectedFolderId);
      }
    }

    if (!searchQuery) return baseDocs;
    return baseDocs.filter(doc => 
      doc.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
      (doc.contractNumber && doc.contractNumber.toLowerCase().includes(searchQuery.toLowerCase())) ||
      doc.tags.some(t => t.toLowerCase().includes(searchQuery.toLowerCase()))
    );
  }, [docs, activeTab, searchQuery, selectedFolderId]);

  const toggleStar = (id: string) => {
    setDocs(prev => prev.map(d => d.id === id ? { ...d, isStarred: !d.isStarred } : d));
  };

  const moveToTrash = (id: string) => {
    setDocs(prev => prev.map(d => d.id === id ? { ...d, isTrashed: true } : d));
    setSelectedDoc(null);
  };

  const handleRenameDoc = (id: string, newName: string) => {
    setDocs(prev => prev.map(d => d.id === id ? { ...d, name: newName } : d));
    if (selectedDoc?.id === id) {
      setSelectedDoc(prev => prev ? { ...prev, name: newName } : null);
    }
  };

  const handleRenameFolder = (id: string, newName: string) => {
    setFolders(prev => prev.map(f => f.id === id ? { ...f, name: newName } : f));
    setEditingFolderId(null);
  };

  const handleUpload = (newFiles: File[], folderId: string | null, metadata: { name: string, contractNumber: string }) => {
    const newDocs: Document[] = newFiles.map((f, i) => ({
      id: `new-${Date.now()}-${i}`,
      name: metadata.name || f.name,
      contractNumber: metadata.contractNumber,
      type: f.name.endsWith('.pdf') ? FileType.PDF : FileType.DOCX,
      ownerId: MOCK_USER.id,
      folderId: folderId,
      lastModified: new Date().toISOString(),
      size: `${(f.size / 1024 / 1024).toFixed(1)} MB`,
      currentVersion: 1,
      versions: [{ id: `v1-${Date.now()}`, versionNumber: 1, updatedAt: new Date().toISOString(), author: MOCK_USER.name, changeNote: 'Initial upload', size: `${(f.size / 1024).toFixed(0)} KB` }],
      tags: [],
      isStarred: false,
      isTrashed: false,
    }));
    setDocs(prev => [...newDocs, ...prev]);
    setIsUploading(false);
  };

  const handleTabChange = (tab: typeof activeTab) => {
    setActiveTab(tab);
    setSelectedFolderId(null);
  };

  const handleFolderClick = (id: string) => {
    setActiveTab('files');
    setSelectedFolderId(id);
  };

  const startRenameFolder = (e: React.MouseEvent, folder: Folder) => {
    e.stopPropagation();
    setEditingFolderId(folder.id);
    setTempFolderName(folder.name);
  };

  return (
    <div className="flex h-screen bg-white text-slate-900 overflow-hidden">
      {/* Sidebar */}
      <aside className={`bg-slate-50 border-r border-slate-200 transition-all duration-300 flex flex-col ${sidebarOpen ? 'w-64' : 'w-16'}`}>
        <div className="p-4 flex items-center gap-3 h-16 border-b border-slate-200">
          <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white shrink-0">
            <Database size={20} />
          </div>
          {sidebarOpen && <span className="font-bold text-lg tracking-tight">DocuMind</span>}
        </div>

        <nav className="flex-1 p-2 space-y-1 overflow-y-auto">
          <NavItem 
            icon={<LayoutDashboard size={20} />} 
            label="Dashboard" 
            active={activeTab === 'dashboard'} 
            collapsed={!sidebarOpen}
            onClick={() => handleTabChange('dashboard')} 
          />
          <NavItem 
            icon={<File size={20} />} 
            label="All Documents" 
            active={activeTab === 'files' && !selectedFolderId} 
            collapsed={!sidebarOpen}
            onClick={() => handleTabChange('files')} 
          />
          <NavItem 
            icon={<Star size={20} />} 
            label="Starred" 
            active={activeTab === 'starred'} 
            collapsed={!sidebarOpen}
            onClick={() => handleTabChange('starred')} 
          />
          <NavItem 
            icon={<Trash2 size={20} />} 
            label="Trash" 
            active={activeTab === 'trash'} 
            collapsed={!sidebarOpen}
            onClick={() => handleTabChange('trash')} 
          />

          <div className="pt-4 pb-2">
             {sidebarOpen && <p className="px-4 text-xs font-semibold text-slate-400 uppercase tracking-wider mb-2">Technical</p>}
             <NavItem 
                icon={<Server size={20} />} 
                label="SQL Architecture" 
                active={activeTab === 'system'} 
                collapsed={!sidebarOpen}
                onClick={() => handleTabChange('system')} 
              />
          </div>

          <div className="pt-4 pb-2">
             {sidebarOpen && <p className="px-4 text-xs font-semibold text-slate-400 uppercase tracking-wider mb-2">Kebeles</p>}
             {sidebarOpen && folders.map(f => (
               <div key={f.id} className="relative group">
                 {editingFolderId === f.id ? (
                    <div className="flex items-center gap-2 px-2 py-1">
                      <input 
                        autoFocus
                        type="text"
                        value={tempFolderName}
                        onChange={(e) => setTempFolderName(e.target.value)}
                        onKeyDown={(e) => e.key === 'Enter' && handleRenameFolder(f.id, tempFolderName)}
                        onBlur={() => handleRenameFolder(f.id, tempFolderName)}
                        className="w-full text-sm bg-white border border-blue-400 rounded px-2 py-1 outline-none"
                      />
                      <button onClick={() => handleRenameFolder(f.id, tempFolderName)} className="text-green-600 p-1">
                        <Check size={14} />
                      </button>
                    </div>
                 ) : (
                   <button 
                    onClick={() => handleFolderClick(f.id)}
                    className={`w-full flex items-center gap-3 px-4 py-2 text-sm rounded-lg transition-colors ${selectedFolderId === f.id ? 'bg-blue-50 text-blue-600 font-semibold' : 'text-slate-600 hover:bg-slate-200'}`}
                   >
                     <FolderIcon size={16} className={selectedFolderId === f.id ? 'text-blue-500' : 'text-slate-400'} />
                     <span className="flex-1 text-left truncate">{f.name}</span>
                     <Pencil 
                        size={12} 
                        className="opacity-0 group-hover:opacity-100 text-slate-400 hover:text-blue-600 transition-opacity" 
                        onClick={(e) => startRenameFolder(e, f)}
                      />
                   </button>
                 )}
               </div>
             ))}
             {!sidebarOpen && <div className="flex justify-center py-2"><FolderIcon size={20} className="text-slate-400" /></div>}
          </div>
        </nav>

        <div className="p-4 border-t border-slate-200">
          <div className="flex items-center gap-3">
            <img src={MOCK_USER.avatar} alt="User" className="w-8 h-8 rounded-full border border-slate-200" />
            {sidebarOpen && (
              <div className="flex-1 overflow-hidden">
                <p className="text-sm font-medium truncate">{MOCK_USER.name}</p>
                <p className="text-xs text-slate-500 truncate">{MOCK_USER.role}</p>
              </div>
            )}
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col min-w-0 bg-white">
        {/* Top Header */}
        <header className="h-16 border-b border-slate-200 flex items-center justify-between px-6 shrink-0">
          <div className="flex items-center gap-4 flex-1">
            <button onClick={() => setSidebarOpen(!sidebarOpen)} className="p-2 hover:bg-slate-100 rounded-lg text-slate-500">
              {sidebarOpen ? <PanelLeftClose size={20} /> : <PanelLeftOpen size={20} />}
            </button>
            <div className="relative max-w-md w-full">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                type="text" 
                placeholder="Search documents, contract #, tags..." 
                className="w-full pl-10 pr-4 py-2 bg-slate-100 border-none rounded-full text-sm focus:ring-2 focus:ring-blue-500 focus:bg-white transition-all outline-none"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
            </div>
          </div>
          <div className="flex items-center gap-3">
            <button 
              onClick={() => setIsUploading(true)}
              className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors shadow-sm"
            >
              <Plus size={18} />
              <span>Upload</span>
            </button>
            <button className="p-2 hover:bg-slate-100 rounded-lg text-slate-500">
              <Settings size={20} />
            </button>
          </div>
        </header>

        {/* Content Area */}
        <div className="flex-1 overflow-y-auto p-6">
          {activeTab === 'system' ? (
            <SystemDesign />
          ) : activeTab === 'files' || activeTab === 'starred' || activeTab === 'trash' ? (
            <div className="space-y-6">
              <div className="flex items-center justify-between">
                <div>
                  <h1 className="text-2xl font-bold text-slate-900 capitalize">
                    {selectedFolderId ? activeFolderName : activeTab}
                  </h1>
                  {selectedFolderId && <p className="text-sm text-slate-500 mt-1">SQL-Backed Records View</p>}
                </div>
                <div className="flex items-center gap-2 text-sm text-slate-500">
                  <Clock size={16} />
                  <span>Last synced: Just now</span>
                </div>
              </div>

              {/* Document List Table */}
              <div className="bg-white border border-slate-200 rounded-xl overflow-hidden shadow-sm">
                <table className="w-full text-left text-sm border-collapse">
                  <thead className="bg-slate-50 border-b border-slate-200 text-slate-500 font-medium">
                    <tr>
                      <th className="px-6 py-4">Name</th>
                      <th className="px-6 py-4">Contract #</th>
                      <th className="px-6 py-4">Last Modified</th>
                      <th className="px-6 py-4">Size</th>
                      <th className="px-6 py-4 text-right">Actions</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    {filteredDocs.length > 0 ? filteredDocs.map(doc => (
                      <tr 
                        key={doc.id} 
                        className={`hover:bg-blue-50/50 cursor-pointer transition-colors ${selectedDoc?.id === doc.id ? 'bg-blue-50' : ''}`}
                        onClick={() => setSelectedDoc(doc)}
                      >
                        <td className="px-6 py-4">
                          <div className="flex items-center gap-3">
                            <div className="shrink-0 p-2 bg-slate-100 rounded-lg">
                              {getFileIcon(doc.type)}
                            </div>
                            <div className="flex flex-col">
                              <span className="font-semibold text-slate-800">{doc.name}</span>
                              <div className="flex items-center gap-1 mt-0.5">
                                {doc.tags.map(tag => (
                                  <span key={tag} className="px-1.5 py-0.5 bg-slate-100 text-slate-500 rounded text-[10px] font-medium uppercase">{tag}</span>
                                ))}
                              </div>
                            </div>
                          </div>
                        </td>
                        <td className="px-6 py-4 text-slate-600 font-medium">
                          {doc.contractNumber || '-'}
                        </td>
                        <td className="px-6 py-4 text-slate-500">
                          {new Date(doc.lastModified).toLocaleDateString()}
                        </td>
                        <td className="px-6 py-4 text-slate-500 font-medium">{doc.size}</td>
                        <td className="px-6 py-4 text-right">
                          <div className="flex items-center justify-end gap-1">
                            <button 
                              onClick={(e) => { e.stopPropagation(); toggleStar(doc.id); }} 
                              className={`p-2 rounded-lg hover:bg-slate-100 ${doc.isStarred ? 'text-amber-400' : 'text-slate-400'}`}
                            >
                              <Star size={18} fill={doc.isStarred ? "currentColor" : "none"} />
                            </button>
                            <button className="p-2 rounded-lg hover:bg-slate-100 text-slate-400">
                              <Share2 size={18} />
                            </button>
                            <button className="p-2 rounded-lg hover:bg-slate-100 text-slate-400">
                              <MoreVertical size={18} />
                            </button>
                          </div>
                        </td>
                      </tr>
                    )) : (
                      <tr>
                        <td colSpan={5} className="px-6 py-12 text-center text-slate-400">
                          <div className="flex flex-col items-center gap-2">
                            <File size={48} className="text-slate-200" />
                            <p>No documents found</p>
                            {selectedFolderId && (
                                <button 
                                    onClick={() => setIsUploading(true)}
                                    className="mt-2 text-blue-600 font-semibold hover:underline"
                                >
                                    Upload the first document to {activeFolderName}
                                </button>
                            )}
                          </div>
                        </td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="md:col-span-2 space-y-6">
                <div className="bg-gradient-to-br from-blue-600 to-indigo-700 rounded-2xl p-8 text-white">
