const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'files' | 'dashboard' | 'starred' | 'trash' | 'system'>('dashboard');
  const [selectedFolderId, setSelectedFolderId] = useState<string | null>(null);
  const [sidebarOpen, setSidebarOpen] = useState(true);
