    setActiveTab('files');
    setSelectedDoc(null);
  };

  const startRenameFolder = (e: React.MouseEvent, folder: Folder) => {
    setEditingFolderId(folder.id);
    setTempFolderName(folder.name);
  };

  const handleAddUser = async (userData: Partial<User>) => {
    const newUser = userData as User;
    setAllUsers(prev => [...prev, newUser]);
    await db.save('users', newUser);
  };

  const handleUpdateUser = async (id: string, updates: Partial<User>) => {
    const updatedUsers = allUsers.map(u => u.id === id ? { ...u, ...updates } : u);
    setAllUsers(updatedUsers);
    const user = updatedUsers.find(u => u.id === id);
    if (user) await db.save('users', user);
    if (id === currentUser?.id && updates.status === 'Deactivated') {
      handleLogout();
    }
  };

  const activeFolderName = useMemo(() => {
    if (!selectedFolderId) return null;
    return folders.find(f => f.id === selectedFolderId)?.name;
  }, [selectedFolderId, folders]);

  const filteredDocs = useMemo(() => {
    let baseDocs = docs;
    if (activeTab === 'starred') {
      baseDocs = docs.filter(d => d.isStarred && !d.isTrashed);
    } else if (activeTab === 'trash') {
      baseDocs = docs.filter(d => d.isTrashed);
    } else {
      baseDocs = docs.filter(d => !d.isTrashed);
      if (selectedFolderId) {
        baseDocs = baseDocs.filter(d => d.folderId === selectedFolderId);
      }
    }
    if (!searchQuery) return baseDocs;
    return baseDocs.filter(doc => 
      doc.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
      (doc.contractNumber && doc.contractNumber.toLowerCase().includes(searchQuery.toLowerCase())) ||
      doc.tags.some(t => t.toLowerCase().includes(searchQuery.toLowerCase()))
    );
  }, [docs, activeTab, searchQuery, selectedFolderId]);

  const toggleStar = async (id: string) => {
    const updated = docs.map(d => d.id === id ? { ...d, isStarred: !d.isStarred } : d);
    setDocs(updated);
    const doc = updated.find(d => d.id === id);
    if (doc) await db.save('documents', doc);
  };

  const moveToTrash = async (id: string) => {
    const updated = docs.map(d => d.id === id ? { ...d, isTrashed: true } : d);
    setDocs(updated);
    setSelectedDoc(null);
    const doc = updated.find(d => d.id === id);
    if (doc) await db.save('documents', doc);
  };

  const handleRenameDoc = async (id: string, newName: string) => {
    const updated = docs.map(d => d.id === id ? { ...d, name: newName } : d);
    setDocs(updated);
    if (selectedDoc?.id === id) {
      setSelectedDoc(prev => prev ? { ...prev, name: newName } : null);
    }
    const doc = updated.find(d => d.id === id);
    if (doc) await db.save('documents', doc);
  };

  const handleRenameFolder = async (id: string, newName: string) => {
    const updated = folders.map(f => f.id === id ? { ...f, name: newName } : f);
    setFolders(updated);
    setEditingFolderId(null);
    const folder = updated.find(f => f.id === id);
    if (folder) await db.save('folders', folder);
  };

  const handleUpload = async (newFiles: File[], folderId: string | null, metadata: { name: string, contractNumber: string }) => {
    const newDocs: Document[] = newFiles.map((f, i) => ({
      id: `new-${Date.now()}-${i}`,
      name: metadata.name || f.name,
      contractNumber: metadata.contractNumber,
      type: f.name.endsWith('.pdf') ? FileType.PDF : FileType.DOCX,
      ownerId: currentUser?.id || 'unknown',
      folderId: folderId,
      lastModified: new Date().toISOString(),
      size: `${(f.size / 1024 / 1024).toFixed(1)} MB`,
      currentVersion: 1,
      versions: [{ id: `v1-${Date.now()}`, versionNumber: 1, updatedAt: new Date().toISOString(), author: currentUser?.name || 'User', changeNote: 'Initial upload', size: `${(f.size / 1024).toFixed(0)} KB` }],
      tags: [],
      isStarred: false,
      isTrashed: false,
    }));
    const updatedDocs = [...newDocs, ...docs];
    setDocs(updatedDocs);
    newDocs.forEach(d => db.save('documents', d));
    const newLog: AuditLog = {
      id: `log-${Date.now()}`,
      docId: newDocs[0].id,
      docName: newDocs[0].name,
      action: 'Created',
      user: currentUser?.name || 'User',
      timestamp: new Date().toISOString()
    };
    const updatedLogs = [newLog, ...auditLogs];
    setAuditLogs(updatedLogs);
    db.save('auditLogs', newLog);
    setIsUploading(false);
  };

  if (!dbReady) return (
    <div className="h-screen w-full flex items-center justify-center bg-white">
      <div className="flex flex-col items-center gap-4">
        <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
        <p className="text-slate-500 font-medium font-bold uppercase text-[10px] tracking-widest">System Bootup...</p>
      </div>
    </div>
  );

  if (!currentUser) {
    return <LoginPage onLogin={handleLogin} lang={lang} />;
  }

  const isAdmin = currentUser.role === 'Admin';

  return (
    <div className="flex h-screen bg-white text-slate-900 overflow-hidden">
      {/* Sidebar */}
      <aside className={`bg-slate-50 border-r border-slate-200 transition-all duration-300 flex flex-col ${sidebarOpen ? 'w-64' : 'w-16'}`}>
        <div className="p-4 flex items-center gap-3 h-16 border-b border-slate-200">
          <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white shrink-0">
            <Database size={20} />
          </div>
          {sidebarOpen && <span className="font-black text-lg tracking-tight">DocuMind</span>}
        </div>

        <nav className="flex-1 p-2 space-y-1 overflow-y-auto">
          <NavItem 
            icon={<LayoutDashboard size={20} />} 
            label={t(lang, 'dashboard')} 
            active={activeTab === 'dashboard'} 
            collapsed={!sidebarOpen}
            onClick={() => setActiveTab('dashboard')} 
          />
          <NavItem 
            icon={<File size={20} />} 
            label={t(lang, 'allDocs')} 
            active={activeTab === 'files' && !selectedFolderId} 
            collapsed={!sidebarOpen}
            onClick={() => { setActiveTab('files'); setSelectedFolderId(null); }} 
          />
          <NavItem 
            icon={<Star size={20} />} 
            label={t(lang, 'starred')} 
            active={activeTab === 'starred'} 
            collapsed={!sidebarOpen}
            onClick={() => { setActiveTab('starred'); setSelectedFolderId(null); }} 
          />
          <NavItem 
            icon={<Trash2 size={20} />} 
            label={t(lang, 'trash')} 
            active={activeTab === 'trash'} 
            collapsed={!sidebarOpen}
            onClick={() => { setActiveTab('trash'); setSelectedFolderId(null); }} 
          />

          {isAdmin && (
            <div className="pt-4 pb-2">
               {sidebarOpen && <p className="px-4 text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Admin</p>}
               <NavItem 
                  icon={<UsersIcon size={20} />} 
                  label={t(lang, 'userMgmt')} 
                  active={activeTab === 'users'} 
                  collapsed={!sidebarOpen}
                  onClick={() => setActiveTab('users')} 
                />
               <NavItem 
                  icon={<Server size={20} />} 
                  label={t(lang, 'sysArch')} 
                  active={activeTab === 'system'} 
                  collapsed={!sidebarOpen}
                  onClick={() => setActiveTab('system')} 
                />
            </div>
          )}

          <div className="pt-4 pb-2">
             {sidebarOpen && <p className="px-4 text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">{t(lang, 'kebele')}</p>}
             {sidebarOpen && folders.map(f => (
               <div key={f.id} className="relative group">
                 {editingFolderId === f.id ? (
                    <div className="flex items-center gap-2 px-2 py-1">
                      <input 
                        autoFocus
                        type="text"
                        value={tempFolderName}
                        onChange={(e) => setTempFolderName(e.target.value)}
                        onKeyDown={(e) => e.key === 'Enter' && handleRenameFolder(f.id, tempFolderName)}
                        onBlur={() => handleRenameFolder(f.id, tempFolderName)}
                        className="w-full text-sm bg-white border border-blue-400 rounded px-2 py-1 outline-none"
                      />
                      <button onClick={() => handleRenameFolder(f.id, tempFolderName)} className="text-green-600 p-1">
                        <Check size={14} />
                      </button>
                    </div>
                 ) : (
                   <button 
                    onClick={() => handleFolderClick(f.id)}
                    className={`w-full flex items-center gap-3 px-4 py-2 text-sm rounded-lg transition-colors ${selectedFolderId === f.id ? 'bg-blue-50 text-blue-600 font-bold' : 'text-slate-600 hover:bg-slate-200'}`}
                   >
                     <FolderIcon size={16} className={selectedFolderId === f.id ? 'text-blue-500' : 'text-slate-400'} />
                     <span className="flex-1 text-left truncate">{f.name}</span>
                     {isAdmin && (
                       <Pencil 
                          size={12} 
                          className="opacity-0 group-hover:opacity-100 text-slate-400 hover:text-blue-600 transition-opacity" 
                          onClick={(e) => { e.stopPropagation(); startRenameFolder(e, f); }}
                        />
                     )}
                   </button>
                 )}
               </div>
             ))}
          </div>
        </nav>

        <div className="p-4 border-t border-slate-200 space-y-4">
          <button 
            onClick={() => setLang(lang === 'en' ? 'am' : 'en')}
            className="w-full flex items-center justify-between px-3 py-2 rounded-xl bg-slate-100 hover:bg-slate-200 transition-all text-xs font-black uppercase tracking-widest text-slate-600"
          >
            <div className="flex items-center gap-2">
              <Languages size={14} />
              {sidebarOpen && <span>{lang === 'en' ? 'Amharic' : 'English'}</span>}
            </div>
            {sidebarOpen && <span className="text-blue-600">{lang === 'en' ? 'EN' : 'AM'}</span>}
          </button>

          <div className={`flex items-center gap-2 px-3 py-1.5 rounded-lg text-[10px] font-black uppercase transition-colors ${isOnline ? 'bg-emerald-50 text-emerald-600' : 'bg-amber-50 text-amber-600'}`}>
            {isOnline ? <Wifi size={14} /> : <WifiOff size={14} />}
            {sidebarOpen && <span>{isOnline ? t(lang, 'online') : t(lang, 'localMode')}</span>}
          </div>
          <div className="flex items-center gap-3 group">
            <img src={currentUser.avatar} alt="User" className="w-8 h-8 rounded-full border border-slate-200" />
            {sidebarOpen && (
              <div className="flex-1 overflow-hidden">
                <p className="text-sm font-bold truncate text-slate-900">{currentUser.name}</p>
                <p className="text-[10px] text-slate-500 font-bold uppercase tracking-tighter">{t(lang, currentUser.role === 'Admin' ? 'admin' : 'user')}</p>
              </div>
            )}
            <button 
              onClick={handleLogout}
              className="p-1.5 text-slate-400 hover:text-rose-500 hover:bg-rose-50 rounded-lg transition-all"
              title={t(lang, 'logOut')}
            >
              <LogOut size={16} />
            </button>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col min-w-0 bg-white">
        <header className="h-16 border-b border-slate-200 flex items-center justify-between px-6 shrink-0">
          <div className="flex items-center gap-4 flex-1">
            <button onClick={() => setSidebarOpen(!sidebarOpen)} className="p-2 hover:bg-slate-100 rounded-lg text-slate-500">
              {sidebarOpen ? <PanelLeftClose size={20} /> : <PanelLeftOpen size={20} />}
            </button>
            <div className="relative max-w-md w-full">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                type="text" 
                placeholder={t(lang, 'searchPlaceholder')} 
                className="w-full pl-10 pr-4 py-2 bg-slate-100 border-none rounded-full text-sm focus:ring-2 focus:ring-blue-500 focus:bg-white transition-all outline-none"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
            </div>
          </div>
          <div className="flex items-center gap-3">
            <button 
              onClick={() => setIsUploading(true)}
              className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-5 py-2.5 rounded-xl text-sm font-bold transition-all shadow-lg shadow-blue-100"
            >
              <Plus size={18} />
              <span>{t(lang, 'addRecord')}</span>
            </button>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-6 bg-white">
          {activeTab === 'dashboard' ? (
            <Dashboard 
              docs={docs} 
              folders={folders} 
              auditLogs={auditLogs} 
              user={currentUser} 
              onSelectDoc={setSelectedDoc}
              onSelectFolder={handleFolderClick}
              lang={lang}
            />
          ) : activeTab === 'system' && isAdmin ? (
            <SystemDesign lang={lang} />
          ) : activeTab === 'users' && isAdmin ? (
            <UserManagement users={allUsers} onAddUser={handleAddUser} onUpdateUser={handleUpdateUser} lang={lang} />
          ) : (
            <div className="space-y-6">
              <div className="flex items-center justify-between">
                <div>
                  <h1 className="text-2xl font-black text-slate-900 tracking-tight capitalize">
                    {selectedFolderId ? activeFolderName : t(lang, activeTab === 'files' ? 'allDocs' : activeTab as any)}
                  </h1>
                </div>
              </div>

              <div className="bg-white border border-slate-200 rounded-3xl overflow-hidden shadow-sm">
                <table className="w-full text-left text-sm">
                  <thead className="bg-slate-50 border-b border-slate-200 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                    <tr>
                      <th className="px-6 py-4">{t(lang, 'name')}</th>
                      <th className="px-6 py-4">{t(lang, 'contractNo')}</th>
                      <th className="px-6 py-4">{t(lang, 'modified')}</th>
                      <th className="px-6 py-4">{t(lang, 'size')}</th>
                      <th className="px-6 py-4 text-right">{t(lang, 'actions')}</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    {filteredDocs.length > 0 ? filteredDocs.map(doc => (
                      <tr 
                        key={doc.id} 
                        className={`hover:bg-blue-50/30 cursor-pointer transition-colors ${selectedDoc?.id === doc.id ? 'bg-blue-50/50' : ''}`}
                        onClick={() => setSelectedDoc(doc)}
                      >
                        <td className="px-6 py-4">
                          <div className="flex items-center gap-3">
                            <div className="shrink-0 p-2 bg-slate-50 rounded-xl border border-slate-100 group-hover:bg-white transition-colors">
                              {getFileIcon(doc.type)}
                            </div>
                            <div className="flex flex-col">
                              <span className="font-bold text-slate-800">{doc.name}</span>
                              <div className="flex items-center gap-1 mt-0.5">
                                {doc.tags.map(tag => (
                                  <span key={tag} className="px-1.5 py-0.5 bg-slate-100 text-slate-500 rounded text-[9px] font-black uppercase tracking-tighter">{tag}</span>
                                ))}
                              </div>
                            </div>
                          </div>
                        </td>
                        <td className="px-6 py-4 text-slate-600 font-bold font-mono text-xs">
                          {doc.contractNumber || '—'}
                        </td>
                        <td className="px-6 py-4 text-slate-500 font-medium">
                          {new Date(doc.lastModified).toLocaleDateString()}
                        </td>
                        <td className="px-6 py-4 text-slate-500 font-bold">{doc.size}</td>
                        <td className="px-6 py-4 text-right">
                          <div className="flex items-center justify-end gap-1">
                            <button 
                              onClick={(e) => { e.stopPropagation(); setPreviewDoc(doc); }}
                              className="p-2 rounded-lg hover:bg-white hover:shadow-sm text-slate-400 hover:text-blue-600 transition-colors"
                              title="Preview"
                            >
                              <Eye size={18} />
                            </button>
                            <button 
                              onClick={(e) => { e.stopPropagation(); toggleStar(doc.id); }} 
                              className={`p-2 rounded-lg hover:bg-white hover:shadow-sm ${doc.isStarred ? 'text-amber-400' : 'text-slate-300'}`}
                            >
                              <Star size={18} fill={doc.isStarred ? "currentColor" : "none"} />
                            </button>
                            <button className="p-2 rounded-lg hover:bg-white hover:shadow-sm text-slate-300">
                              <MoreVertical size={18} />
                            </button>
                          </div>
                        </td>
                      </tr>
                    )) : (
                      <tr>
                        <td colSpan={5} className="px-6 py-20 text-center">
                          <div className="flex flex-col items-center gap-3 opacity-30">
                            <File size={64} className="text-slate-900" />
                            <p className="font-black uppercase text-xs tracking-widest">No local documents found</p>
                          </div>
                        </td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          )}
        </div>
      </main>

      {/* Right Details Panel */}
      {selectedDoc && (
        <aside className="w-96 bg-white border-l border-slate-200 overflow-y-auto flex flex-col shrink-0 animate-in slide-in-from-right duration-300">
          <div className="h-16 flex items-center justify-between px-6 border-b border-slate-200 sticky top-0 bg-white z-10">
            <h3 className="font-black text-slate-900 uppercase text-xs tracking-widest">{t(lang, 'details')}</h3>
            <button onClick={() => setSelectedDoc(null)} className="p-2 hover:bg-slate-100 rounded-lg text-slate-500">
              <X size={20} />
            </button>
          </div>
          <DocumentDetails 
            doc={selectedDoc} 
            onRename={handleRenameDoc} 
            onTrash={() => moveToTrash(selectedDoc.id)} 
            onPreview={() => setPreviewDoc(selectedDoc)}
            lang={lang} 
          />
        </aside>
      )}

      {/* Document Preview Modal */}
      {previewDoc && (
        <DocumentPreview 
          doc={previewDoc} 
          onClose={() => setPreviewDoc(null)} 
          lang={lang} 
        />
      )}

      {/* Upload Modal */}
      {isUploading && (
        <FileUploader 
          folders={folders} 
          initialFolderId={selectedFolderId}
          onUpload={handleUpload} 
          onClose={() => setIsUploading(false)} 
          lang={lang}
        />
      )}
    </div>
  );
};

const NavItem: React.FC<{ icon: React.ReactNode, label: string, active: boolean, onClick: () => void, collapsed: boolean }> = ({ icon, label, active, onClick, collapsed }) => (
  <button 
    onClick={onClick}
    className={`w-full flex items-center gap-3 px-3 py-3 rounded-2xl text-sm transition-all ${
      active 
      ? 'bg-blue-600 text-white font-bold shadow-lg shadow-blue-200' 
      : 'text-slate-600 hover:bg-slate-100 font-medium'
    }`}
    title={collapsed ? label : undefined}
  >
    <div className="shrink-0">{icon}</div>
    {!collapsed && <span>{label}</span>}
  </button>
);

export default App;

import React, { useState, useEffect } from 'react';
import { Document } from '../types';
import { getFileIcon } from '../constants';
import { Download, History, Share2, Trash2, Info, User, Calendar, Database, Shield, Pencil, Check, X as CloseIcon, Hash, Eye } from 'lucide-react';
import { Language, t } from '../translations';

interface Props {
  doc: Document;
  onRename: (id: string, newName: string) => void;
  onTrash: () => void;
  onPreview: () => void;
  lang: Language;
}

const DocumentDetails: React.FC<Props> = ({ doc, onRename, onTrash, onPreview, lang }) => {
  const [isRenaming, setIsRenaming] = useState(false);
  const [tempName, setTempName] = useState(doc.name);

  useEffect(() => {
    setTempName(doc.name);
    setIsRenaming(false);
  }, [doc.id]);

  const handleConfirmRename = () => {
    if (tempName.trim() && tempName !== doc.name) {
      onRename(doc.id, tempName);
    }
    setIsRenaming(false);
  };

  return (
    <div className="flex flex-col h-full">
      {/* Overview */}
      <div className="p-6 text-center space-y-4 border-b border-slate-100">
        <div className="inline-flex p-4 bg-slate-50 rounded-2xl border border-slate-100 shadow-sm mx-auto">
          {getFileIcon(doc.type)}
        </div>

        <div className="space-y-1">
          {isRenaming ? (
            <div className="flex items-center gap-2 px-4">
              <input 
                autoFocus
                type="text" 
                className="w-full text-center text-sm font-bold border-b-2 border-blue-500 outline-none pb-1"
                value={tempName}
                onChange={(e) => setTempName(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleConfirmRename()}
              />
              <button onClick={handleConfirmRename} className="p-1 text-green-600 hover:bg-green-50 rounded">
                <Check size={16} />
              </button>
              <button onClick={() => { setIsRenaming(false); setTempName(doc.name); }} className="p-1 text-red-600 hover:bg-red-50 rounded">
                <CloseIcon size={16} />
              </button>
            </div>
          ) : (
            <div className="flex items-center justify-center gap-2 group">
              <h2 className="text-lg font-bold text-slate-900 break-words line-clamp-2">{doc.name}</h2>
              <button 
                onClick={() => setIsRenaming(true)}
                className="opacity-0 group-hover:opacity-100 p-1 text-slate-400 hover:text-blue-600 transition-all"
              >
                <Pencil size={14} />
              </button>
            </div>
          )}
          {doc.contractNumber && (
            <p className="text-xs font-bold text-blue-600 flex items-center justify-center gap-1">
              <Hash size={12} /> {doc.contractNumber}
            </p>
          )}
          <p className="text-sm text-slate-500 mt-1 uppercase tracking-wider font-semibold">{t(lang, 'version')} {doc.currentVersion}</p>
        </div>

        <div className="flex items-center justify-center gap-2 pt-2">
          <ActionButton icon={<Eye size={18} />} label="Preview" onClick={onPreview} />
          <ActionButton icon={<Download size={18} />} label={t(lang, 'download')} />
          <ActionButton icon={<Share2 size={18} />} label={t(lang, 'share')} />
          <ActionButton icon={<Trash2 size={18} />} label={t(lang, 'delete')} variant="danger" onClick={onTrash} />
        </div>
      </div>

      {/* Info Sections */}
      <div className="flex-1 overflow-y-auto p-6 space-y-8">
        <section className="space-y-4">
          <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
            <Info size={14} /> {t(lang, 'details')}
          </h3>
          <div className="grid grid-cols-2 gap-4">
            <InfoItem icon={<User size={14} />} label={lang === 'en' ? "Owner" : "ባለቤት"} value="System Admin" />
            <InfoItem icon={<Database size={14} />} label={t(lang, 'size')} value={doc.size} />
            <InfoItem icon={<Calendar size={14} />} label={t(lang, 'modified')} value={new Date(doc.lastModified).toLocaleDateString()} />
            <InfoItem icon={<Shield size={14} />} label={lang === 'en' ? "Security" : "ደህንነት"} value="AES-256" />
          </div>
        </section>

        <section className="space-y-4">
          <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
            <History size={14} /> {t(lang, 'history')}
          </h3>
          <div className="space-y-3">
            {doc.versions.map((v, idx) => (
              <div key={v.id} className={`p-3 rounded-xl border ${idx === 0 ? 'bg-blue-50 border-blue-100' : 'bg-white border-slate-100 hover:bg-slate-50'} transition-all group`}>
                <div className="flex items-center justify-between mb-1">
                  <span className="text-xs font-bold text-slate-800">v{v.versionNumber}</span>
                  <span className="text-[10px] text-slate-400 font-medium">{new Date(v.updatedAt).toLocaleDateString()}</span>
                </div>
                <p className="text-xs text-slate-600 line-clamp-1">{v.changeNote}</p>
              </div>
            ))}
          </div>
        </section>

        <section className="space-y-4 pb-8">
           <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest">{t(lang, 'tags')}</h3>
           <div className="flex flex-wrap gap-2">
              {doc.tags.map(tag => (
                <span key={tag} className="px-2 py-1 bg-slate-100 text-slate-600 rounded-lg text-xs font-medium border border-slate-200">#{tag}</span>
              ))}
              <button className="px-2 py-1 bg-white border border-dashed border-slate-300 text-slate-400 rounded-lg text-xs font-medium hover:border-blue-400 hover:text-blue-500 transition-all">+ {lang === 'en' ? 'Add' : 'አክል'}</button>
           </div>
        </section>
      </div>
    </div>
  );
};

