      ? 'bg-blue-600 text-white font-bold shadow-lg shadow-blue-200' 
      : 'text-slate-600 hover:bg-slate-100 font-medium'
    }`}
    title={collapsed ? label : undefined}
  >
    <div className="shrink-0">{icon}</div>
    {!collapsed && <span>{label}</span>}
  </button>
);

export default App;

import React, { useState } from 'react';
import { X, Download, Printer, Maximize2, FileText, ChevronLeft, ChevronRight, ZoomIn, ZoomOut, Image as ImageIcon } from 'lucide-react';
import { Document, FileType } from '../types';
import { getFileIcon } from '../constants';
import { Language, t } from '../translations';

interface DocumentPreviewProps {
  doc: Document;
  onClose: () => void;
  lang: Language;
}

const DocumentPreview: React.FC<DocumentPreviewProps> = ({ doc, onClose, lang }) => {
  const [zoom, setZoom] = useState(100);
  const isImage = doc.type === FileType.IMG;
  const imageUrl = doc.previewUrl || doc.previewContent; // Could be a URL or base64 string

  const handleZoomIn = () => setZoom(prev => Math.min(prev + 25, 300));
  const handleZoomOut = () => setZoom(prev => Math.max(prev - 25, 25));

  return (
    <div className="fixed inset-0 z-[100] flex flex-col bg-slate-900/95 backdrop-blur-md animate-in fade-in duration-300">
      {/* Top Toolbar */}
      <header className="h-16 flex items-center justify-between px-6 bg-slate-900 border-b border-slate-800 shrink-0">
        <div className="flex items-center gap-4">
          <button 
            onClick={onClose}
            className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded-lg transition-all"
          >
            <X size={20} />
          </button>
          <div className="flex items-center gap-3">
            <div className="p-2 bg-slate-800 rounded-lg border border-slate-700">
              {getFileIcon(doc.type)}
            </div>
            <div>
              <h2 className="text-white font-bold text-sm leading-none mb-1">{doc.name}</h2>
              <p className="text-slate-500 text-[10px] uppercase font-bold tracking-widest">
                {t(lang, 'version')} {doc.currentVersion} • {doc.size}
              </p>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-2">
          <ToolbarButton icon={<ZoomOut size={18} />} label="Zoom Out" onClick={handleZoomOut} />
          <div className="px-3 py-1 bg-slate-800 text-slate-300 text-xs font-bold rounded-lg border border-slate-700 w-16 text-center">
            {zoom}%
          </div>
          <ToolbarButton icon={<ZoomIn size={18} />} label="Zoom In" onClick={handleZoomIn} />
          <div className="w-px h-6 bg-slate-700 mx-2" />
          <ToolbarButton icon={<Printer size={18} />} label="Print" />
          <ToolbarButton icon={<Download size={18} />} label={t(lang, 'download')} />
          <button className="ml-2 bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-xl text-sm font-bold transition-all shadow-lg shadow-blue-900/20">
            {t(lang, 'share')}
          </button>
        </div>
      </header>

      {/* Main Viewport */}
      <div className="flex-1 overflow-auto flex items-center justify-center p-8 bg-slate-800/50 relative">
        {isImage ? (
           <div className="relative group max-w-full flex justify-center animate-in zoom-in duration-500">
              {imageUrl ? (
                <img 
                  src={imageUrl} 
                  alt={doc.name} 
                  style={{ transform: `scale(${zoom / 100})` }}
                  className="max-w-full max-h-[85vh] object-contain rounded-lg shadow-2xl border-4 border-slate-900 transition-transform duration-200 ease-out origin-center" 
                />
              ) : (
                <div className="bg-white/5 p-20 rounded-2xl border border-white/10 flex flex-col items-center gap-4 text-slate-400">
                  <ImageIcon size={64} className="opacity-20" />
                  <p className="font-bold">Image source not found</p>
                </div>
              )}
           </div>
        ) : (
          <div 
            style={{ transform: `scale(${zoom / 100})` }}
            className="bg-white w-full max-w-4xl min-h-[1100px] shadow-2xl rounded-sm p-16 relative animate-in slide-in-from-bottom-4 duration-500 transition-transform duration-200 ease-out origin-top"
          >
            {/* Document Text Content Rendering */}
            <div className="prose prose-slate max-w-none">
              {doc.previewContent ? (
                <pre className="whitespace-pre-wrap font-sans text-slate-800 text-lg leading-relaxed">
                  {doc.previewContent}
                </pre>
              ) : (
                <div className="flex flex-col items-center justify-center py-40 text-slate-300">
                  <FileText size={80} className="mb-4 opacity-20" />
                  <p className="font-bold text-lg">Preview not available for this file type</p>
                  <p className="text-sm">Please download the file to view its full content.</p>
                </div>
              )}
            </div>

            {/* Page Indicator (Mock for Docs) */}
            <div className="absolute bottom-8 left-1/2 -translate-x-1/2 flex items-center gap-4 px-4 py-2 bg-slate-900/80 text-white rounded-full text-xs font-bold backdrop-blur-md">
              <button className="hover:text-blue-400 transition-colors"><ChevronLeft size={16} /></button>
              <span>Page 1 of 1</span>
              <button className="hover:text-blue-400 transition-colors"><ChevronRight size={16} /></button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

const ToolbarButton = ({ icon, label, onClick }: { icon: React.ReactNode, label: string, onClick?: () => void }) => (
  <button 
    onClick={onClick}
    className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded-lg transition-all"
    title={label}
  >
    {icon}
  </button>
);

