import { Document, FileType } from '../types';

const API_BASE = '/api'; // This works via the IIS Reverse Proxy defined in web.config

export const apiService = {
  async getDocuments(): Promise<Document[]> {
    try {
      const response = await fetch(`${API_BASE}/documents`);
      if (!response.ok) throw new Error('Network response was not ok');
      return await response.json();
    } catch (error) {
      console.error('Failed to fetch from SQL:', error);
      throw error;
    }
  },

  async uploadDocument(doc: Document, files: File[]): Promise<void> {
    const formData = new FormData();
    formData.append('name', doc.name);
    formData.append('contractNumber', doc.contractNumber || '');
    formData.append('ownerId', doc.ownerId);
    formData.append('size', doc.size);

    // In a real app, we'd append actual files
    files.forEach(file => formData.append('files', file));

    const response = await fetch(`${API_BASE}/documents`, {
      method: 'POST',
      body: formData,
    });

    if (!response.ok) throw new Error('Failed to upload to SQL Server');
  },

  async updateDocumentStatus(id: string, status: { isStarred?: boolean, isTrashed?: boolean }): Promise<void> {
    const response = await fetch(`${API_BASE}/documents/${id}`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(status),
    });

    if (!response.ok) throw new Error('Failed to update SQL Server');
  }
};

import React, { useState, useMemo, useEffect } from 'react';
import { 
  Folder as FolderIcon, 
  File, 
  Search, 
  Plus, 
  Clock, 
  Star, 
  Trash2, 
  LayoutDashboard, 
  Database, 
  Settings,
  PanelLeftClose,
  PanelLeftOpen,
  MoreVertical,
  Share2,
  X,
  Pencil,
  Check,
  Server,
  Wifi,
  WifiOff,
  Users as UsersIcon,
  LogOut,
  Languages,
  Eye,
  RefreshCw
} from 'lucide-react';
import { MOCK_DOCS, MOCK_FOLDERS, MOCK_USER, MOCK_AUDIT_LOGS, getFileIcon } from './constants';
import { Document, Folder, FileType, AuditLog, User } from './types';
import FileUploader from './components/FileUploader';
import DocumentDetails from './components/DocumentDetails';
import DocumentPreview from './components/DocumentPreview';
import SystemDesign from './components/SystemDesign';
import Dashboard from './components/Dashboard';
import LoginPage from './components/LoginPage';
import UserManagement from './components/UserManagement';
import { db } from './db';
import { Language, t } from './translations';
import { apiService } from './services/apiService';

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>(() => (localStorage.getItem('documind_lang') as Language) || 'en');
  const [activeTab, setActiveTab] = useState<'files' | 'dashboard' | 'starred' | 'trash' | 'system' | 'users'>('dashboard');
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [allUsers, setAllUsers] = useState<User[]>([]);
  const [selectedFolderId, setSelectedFolderId] = useState<string | null>(null);
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedDoc, setSelectedDoc] = useState<Document | null>(null);
  const [previewDoc, setPreviewDoc] = useState<Document | null>(null);
  const [docs, setDocs] = useState<Document[]>([]);
  const [folders, setFolders] = useState<Folder[]>([]);
  const [auditLogs, setAuditLogs] = useState<AuditLog[]>([]);
  const [isUploading, setIsUploading] = useState(false);
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [dbReady, setDbReady] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);

  const [editingFolderId, setEditingFolderId] = useState<string | null>(null);
  const [tempFolderName, setTempFolderName] = useState('');

  // Persist language
  useEffect(() => {
    localStorage.setItem('documind_lang', lang);
  }, [lang]);

  const syncWithSQL = async () => {
    if (!navigator.onLine) return;
    setIsSyncing(true);
    try {
      const sqlDocs = await apiService.getDocuments();
      if (sqlDocs && sqlDocs.length > 0) {
        // Merge SQL docs with local ones (SQL wins as source of truth for IDs)
        setDocs(prev => {
          const merged = [...prev];
          sqlDocs.forEach(sqlDoc => {
            const idx = merged.findIndex(d => d.id === sqlDoc.id);
            if (idx > -1) merged[idx] = sqlDoc;
            else merged.unshift(sqlDoc);
          });
          return merged;
        });
        // Save to IndexedDB for offline persistence
        for (const doc of sqlDocs) {
          await db.save('documents', doc);
        }
      }
    } catch (err) {
      console.warn("SQL Sync failed, continuing in Local Mode");
    } finally {
      setIsSyncing(false);
    }
  };

  // Initialize DB and Load Data
  useEffect(() => {
    const initData = async () => {
      await db.init();
      const savedDocs = await db.getAll<Document>('documents');
      const savedFolders = await db.getAll<Folder>('folders');
      const savedLogs = await db.getAll<AuditLog>('auditLogs');
      const savedUsers = await db.getAll<User>('users');

      let finalUsers = savedUsers;

      if (savedUsers.length === 0) {
        const initialUsers: User[] = [
          { id: 'u-admin', name: 'System Admin', email: 'admin@documind.pro', password: 'admin123', avatar: 'https://picsum.photos/seed/admin/100/100', role: 'Admin', status: 'Active' },
          { id: 'u-user', name: 'Standard User', email: 'user@documind.pro', password: 'user123', avatar: 'https://picsum.photos/seed/user/100/100', role: 'User', status: 'Active' }
        ];
        initialUsers.forEach(u => db.save('users', u));
        finalUsers = initialUsers;
      } else {
        finalUsers = savedUsers.map(u => u.id === 'u-admin' ? { ...u, status: 'Active' as const } : u);
        const adminUser = finalUsers.find(u => u.id === 'u-admin');
        if (adminUser) db.save('users', adminUser);
      }
      setAllUsers(finalUsers);

      if (savedDocs.length === 0 && savedFolders.length === 0) {
        setDocs(MOCK_DOCS);
        setFolders(MOCK_FOLDERS);
        setAuditLogs(MOCK_AUDIT_LOGS);
        MOCK_DOCS.forEach(d => db.save('documents', d));
        MOCK_FOLDERS.forEach(f => db.save('folders', f));
        MOCK_AUDIT_LOGS.forEach(l => db.save('auditLogs', l));
      } else {
        setDocs(savedDocs);
        setFolders(savedFolders);
        setAuditLogs(savedLogs);
      }

      const savedSession = localStorage.getItem('documind_session');
      if (savedSession) {
        const userId = JSON.parse(savedSession).id;
        const user = finalUsers.find(u => u.id === userId);
        if (user && user.status === 'Active') {
          setCurrentUser(user);
        }
      }
      setDbReady(true);

      // Attempt first SQL sync
      if (navigator.onLine) {
        syncWithSQL();
      }
    };
    initData();
    const handleOnline = () => { setIsOnline(true); syncWithSQL(); };
    const handleOffline = () => setIsOnline(false);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  const handleLogin = async (email: string, pass: string): Promise<boolean> => {
    const user = allUsers.find(u => u.email === email && u.password === pass);
    if (user && user.status === 'Active') {
      setCurrentUser(user);
      localStorage.setItem('documind_session', JSON.stringify({ id: user.id }));
      return true;
    }
    return false;
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('documind_session');
    setActiveTab('dashboard');
  };

  const handleFolderClick = (id: string) => {
    setSelectedFolderId(id);
    setActiveTab('files');
    setSelectedDoc(null);
  };

  const startRenameFolder = (e: React.MouseEvent, folder: Folder) => {
    setEditingFolderId(folder.id);
    setTempFolderName(folder.name);
  };

  const handleAddUser = async (userData: Partial<User>) => {
    const newUser = userData as User;
    setAllUsers(prev => [...prev, newUser]);
    await db.save('users', newUser);
  };

  const handleUpdateUser = async (id: string, updates: Partial<User>) => {
    const updatedUsers = allUsers.map(u => u.id === id ? { ...u, ...updates } : u);
    setAllUsers(updatedUsers);
    const user = updatedUsers.find(u => u.id === id);
    if (user) await db.save('users', user);
    if (id === currentUser?.id && updates.status === 'Deactivated') {
      handleLogout();
    }
  };

  const activeFolderName = useMemo(() => {
    if (!selectedFolderId) return null;
    return folders.find(f => f.id === selectedFolderId)?.name;
  }, [selectedFolderId, folders]);

  const filteredDocs = useMemo(() => {
    let baseDocs = docs;
    if (activeTab === 'starred') {
      baseDocs = docs.filter(d => d.isStarred && !d.isTrashed);
    } else if (activeTab === 'trash') {
      baseDocs = docs.filter(d => d.isTrashed);
    } else {
      baseDocs = docs.filter(d => !d.isTrashed);
      if (selectedFolderId) {
        baseDocs = baseDocs.filter(d => d.folderId === selectedFolderId);
      }
    }
    if (!searchQuery) return baseDocs;
    return baseDocs.filter(doc => 
      doc.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
      (doc.contractNumber && doc.contractNumber.toLowerCase().includes(searchQuery.toLowerCase())) ||
      doc.tags.some(t => t.toLowerCase().includes(searchQuery.toLowerCase()))
    );
  }, [docs, activeTab, searchQuery, selectedFolderId]);

  const toggleStar = async (id: string) => {
    const updated = docs.map(d => d.id === id ? { ...d, isStarred: !d.isStarred } : d);
    setDocs(updated);
    const doc = updated.find(d => d.id === id);
    if (doc) {
      await db.save('documents', doc);
      if (isOnline) {
        await apiService.updateDocumentStatus(id, { isStarred: doc.isStarred });
      }
    }
  };

  const moveToTrash = async (id: string) => {
    const updated = docs.map(d => d.id === id ? { ...d, isTrashed: true } : d);
    setDocs(updated);
    setSelectedDoc(null);
    const doc = updated.find(d => d.id === id);
    if (doc) {
      await db.save('documents', doc);
      if (isOnline) {
        await apiService.updateDocumentStatus(id, { isTrashed: true });
      }
    }
  };

  const handleRenameDoc = async (id: string, newName: string) => {
    const updated = docs.map(d => d.id === id ? { ...d, name: newName } : d);
    setDocs(updated);
    if (selectedDoc?.id === id) {
      setSelectedDoc(prev => prev ? { ...prev, name: newName } : null);
    }
    const doc = updated.find(d => d.id === id);
    if (doc) await db.save('documents', doc);
  };

  const handleRenameFolder = async (id: string, newName: string) => {
    const updated = folders.map(f => f.id === id ? { ...f, name: newName } : f);
    setFolders(updated);
    setEditingFolderId(null);
    const folder = updated.find(f => f.id === id);
    if (folder) await db.save('folders', folder);
  };

  const getDocType = (fileName: string): FileType => {
    const ext = fileName.split('.').pop()?.toLowerCase();
    if (ext === 'pdf') return FileType.PDF;
    if (ext === 'xlsx' || ext === 'csv') return FileType.XLSX;
    if (['jpg', 'jpeg', 'png', 'webp', 'gif'].includes(ext || '')) return FileType.IMG;
    return FileType.DOCX;
  };

  const handleUpload = async (newFiles: File[], folderId: string | null, metadata: { name: string, contractNumber: string }) => {
    const newDocs: Document[] = newFiles.map((f, i) => ({
      id: `new-${Date.now()}-${i}`,
      name: metadata.name || f.name,
      contractNumber: metadata.contractNumber,
      type: getDocType(f.name),
      ownerId: currentUser?.id || 'unknown',
      folderId: folderId,
      lastModified: new Date().toISOString(),
      size: `${(f.size / 1024 / 1024).toFixed(1)} MB`,
      currentVersion: 1,
      versions: [{ id: `v1-${Date.now()}`, versionNumber: 1, updatedAt: new Date().toISOString(), author: currentUser?.name || 'User', changeNote: 'Initial upload', size: `${(f.size / 1024).toFixed(0)} KB` }],
      tags: [],
      isStarred: false,
      isTrashed: false,
    }));

    // 1. Update local UI immediately
    const updatedDocs = [...newDocs, ...docs];
    setDocs(updatedDocs);

    // 2. Save to local IndexedDB
    for (const d of newDocs) {
      await db.save('documents', d);

      // 3. Sync to SQL Server if online
      if (isOnline) {
        try {
          await apiService.uploadDocument(d, newFiles);
        } catch (err) {
          console.error("SQL Upload failed, doc remains in local storage");
        }
      }
    }

    const newLog: AuditLog = {
      id: `log-${Date.now()}`,
      docId: newDocs[0].id,
      docName: newDocs[0].name,
      action: 'Created',
      user: currentUser?.name || 'User',
      timestamp: new Date().toISOString()
    };
    const updatedLogs = [newLog, ...auditLogs];
    setAuditLogs(updatedLogs);
    db.save('auditLogs', newLog);
    setIsUploading(false);
  };

  if (!dbReady) return (
    <div className="h-screen w-full flex items-center justify-center bg-white">
      <div className="flex flex-col items-center gap-4">
        <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
        <p className="text-slate-500 font-medium font-bold uppercase text-[10px] tracking-widest">System Bootup...</p>
      </div>
    </div>
  );

  if (!currentUser) {
    return <LoginPage onLogin={handleLogin} lang={lang} />;
  }

  const isAdmin = currentUser.role === 'Admin';

  return (
    <div className="flex h-screen bg-white text-slate-900 overflow-hidden">
      {/* Sidebar */}
      <aside className={`bg-slate-50 border-r border-slate-200 transition-all duration-300 flex flex-col ${sidebarOpen ? 'w-64' : 'w-16'}`}>
        <div className="p-4 flex items-center gap-3 h-16 border-b border-slate-200">
          <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white shrink-0">
            <Database size={20} />
          </div>
          {sidebarOpen && <span className="font-black text-lg tracking-tight">DocuMind</span>}
        </div>

        <nav className="flex-1 p-2 space-y-1 overflow-y-auto">
          <NavItem 
