import { Document, FileType } from '../types';

const API_BASE = '/api'; // This works via the IIS Reverse Proxy defined in web.config

export const apiService = {
  async getDocuments(): Promise<Document[]> {
    try {
      const response = await fetch(`${API_BASE}/documents`);

      // Handle cases where the Bridge API might not be configured yet
      if (response.status === 404) {
        console.warn('SQL Bridge API not found at /api/documents. Ensure IIS and Node.js bridge are running.');
        return [];
      }

      if (!response.ok) {
        const errorText = await response.text();
        throw new Error(`SQL Sync Error (${response.status}): ${errorText || 'Unknown error'}`);
      }

      return await response.json();
    } catch (error) {
      // Don't throw for simple connection errors, just log and return empty
      console.error('SQL Connection failed:', error);
      return [];
    }
  },

  async uploadDocument(doc: Document, files: File[]): Promise<void> {
    const formData = new FormData();
    formData.append('id', doc.id);
    formData.append('name', doc.name);
    formData.append('contractNumber', doc.contractNumber || '');
    formData.append('ownerId', doc.ownerId);
    formData.append('folderId', doc.folderId || '');
    formData.append('size', doc.size);

    // Append actual files if provided
    files.forEach(file => formData.append('files', file));

    try {
      const response = await fetch(`${API_BASE}/documents`, {
        method: 'POST',
        body: formData,
      });

      if (!response.ok) {
        const errorText = await response.text();
        throw new Error(`Upload failed: ${errorText}`);
      }
    } catch (error) {
      console.error('Failed to sync upload to SQL Server:', error);
      throw error;
    }
  },

  async updateDocumentStatus(id: string, status: { isStarred?: boolean, isTrashed?: boolean }): Promise<void> {
    try {
      const response = await fetch(`${API_BASE}/documents/${id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(status),
      });

      if (!response.ok) {
        console.warn(`Failed to update status in SQL for ${id}`);
      }
    } catch (error) {
      console.error('SQL Status update failed:', error);
    }
  }
};

/**
 * DocuMind Pro - SQL Server Bridge API
 * Dependencies: npm install express mssql cors dotenv multer
 */

const express = require('express');
const sql = require('mssql');
const cors = require('cors');
const multer = require('multer');
require('dotenv').config();

const app = express();
app.use(cors());
app.use(express.json());

// SQL Server Configuration
const dbConfig = {
    user: process.env.DB_USER || 'sa',
    password: process.env.DB_PASSWORD || 'YourStrongPassword',
    server: process.env.DB_SERVER || 'localhost',
    database: process.env.DB_NAME || 'DocuMind',
    options: {
        encrypt: true,
        trustServerCertificate: true // For local development
    }
};

// Use a connection pool to handle requests reliably
let poolPromise = sql.connect(dbConfig);

// File Upload Configuration
const storage = multer.diskStorage({
    destination: './uploads/',
    filename: (req, file, cb) => {
        cb(null, `${Date.now()}-${file.originalname}`);
    }
});
const upload = multer({ storage });

// Routes
// 1. Get All Documents
app.get('/api/documents', async (req, res) => {
    try {
        const pool = await poolPromise;
        const result = await pool.request().query('SELECT * FROM Documents WHERE IsTrashed = 0');
        res.json(result.recordset);
    } catch (err) {
        console.error('GET Documents Error:', err);
        res.status(500).send(err.message);
    }
});

// 2. Upload Document & Save Metadata
app.post('/api/documents', upload.array('files'), async (req, res) => {
    const { id, name, contractNumber, ownerId, folderId, size } = req.body;
    try {
        const pool = await poolPromise;
        await pool.request()
            .input('ID', sql.NVarChar, id)
            .input('Name', sql.NVarChar, name)
            .input('ContractNumber', sql.NVarChar, contractNumber)
            .input('OwnerID', sql.NVarChar, ownerId)
            .input('FolderID', sql.NVarChar, folderId)
            .input('Size', sql.NVarChar, size)
            .query(`
                IF NOT EXISTS (SELECT 1 FROM Documents WHERE ID = @ID)
                INSERT INTO Documents (ID, Name, ContractNumber, OwnerID, FolderID, Size) 
                VALUES (@ID, @Name, @ContractNumber, @OwnerID, @FolderID, @Size)
            `);

        res.status(201).json({ message: 'Document synchronized successfully' });
    } catch (err) {
        console.error('POST Document Error:', err);
        res.status(500).send(err.message);
    }
});

// 3. Update Status (Star/Trash)
app.patch('/api/documents/:id', async (req, res) => {
    const { id } = req.params;
    const { isStarred, isTrashed } = req.body;
    try {
        const pool = await poolPromise;
        const request = pool.request().input('ID', sql.NVarChar, id);

        let query = 'UPDATE Documents SET ';
        const updates = [];
        if (isStarred !== undefined) {
            request.input('IsStarred', sql.Bit, isStarred);
            updates.push('IsStarred = @IsStarred');
        }
        if (isTrashed !== undefined) {
            request.input('IsTrashed', sql.Bit, isTrashed);
            updates.push('IsTrashed = @IsTrashed');
        }

        if (updates.length === 0) return res.json({ message: 'No changes provided' });

        query += updates.join(', ') + ' WHERE ID = @ID';
        await request.query(query);

        res.json({ message: 'Updated successfully' });
    } catch (err) {
        console.error('PATCH Document Error:', err);
        res.status(500).send(err.message);
    }
});

// Start Server
const PORT = process.env.PORT || 5000;
app.listen(PORT, () => {
    console.log(`Bridge API running on port ${PORT}`);
});

