import React, { useState, useEffect } from 'react';
import { Document, FileType } from '../types';
import { getFileIcon } from '../constants';
import { Download, History, Share2, Trash2, Info, User, Calendar, Database, Shield, Pencil, Check, X as CloseIcon, Hash, Eye, Maximize, Printer } from 'lucide-react';
import { Language, t } from '../translations';

interface Props {
  doc: Document;
  onRename: (id: string, newName: string) => void;
  onTrash: () => void;
  onPreview: () => void;
  onPrint: () => void;
  lang: Language;
}

const DocumentDetails: React.FC<Props> = ({ doc, onRename, onTrash, onPreview, onPrint, lang }) => {
  const [isRenaming, setIsRenaming] = useState(false);
  const [tempName, setTempName] = useState(doc.name);

  useEffect(() => {
    setTempName(doc.name);
    setIsRenaming(false);
  }, [doc.id]);

  const handleConfirmRename = () => {
    if (tempName.trim() && tempName !== doc.name) {
      onRename(doc.id, tempName);
    }
    setIsRenaming(false);
  };

  const isImage = doc.type === FileType.IMG;
  const imageUrl = doc.previewUrl || doc.previewContent;

  return (
    <div className="flex flex-col h-full">
      {/* Overview */}
      <div className="p-6 text-center space-y-4 border-b border-slate-100">
        <div className="relative group mx-auto inline-block">
          {isImage && imageUrl ? (
            <div 
              className="w-40 h-40 bg-slate-50 rounded-2xl border border-slate-100 shadow-sm overflow-hidden cursor-pointer relative"
              onClick={onPreview}
            >
              <img src={imageUrl} alt={doc.name} className="w-full h-full object-cover transition-transform group-hover:scale-110" />
              <div className="absolute inset-0 bg-black/0 group-hover:bg-black/20 transition-colors flex items-center justify-center opacity-0 group-hover:opacity-100">
                <Maximize className="text-white" size={24} />
              </div>
            </div>
          ) : (
            <div className="inline-flex p-6 bg-slate-50 rounded-2xl border border-slate-100 shadow-sm">
              {React.cloneElement(getFileIcon(doc.type) as React.ReactElement<any>, { size: 32 })}
            </div>
          )}
        </div>

        <div className="space-y-1">
          {isRenaming ? (
            <div className="flex items-center gap-2 px-4">
              <input 
                autoFocus
                type="text" 
                className="w-full text-center text-sm font-bold border-b-2 border-blue-500 outline-none pb-1"
                value={tempName}
                onChange={(e) => setTempName(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleConfirmRename()}
              />
              <button onClick={handleConfirmRename} className="p-1 text-green-600 hover:bg-green-50 rounded">
                <Check size={16} />
              </button>
              <button onClick={() => { setIsRenaming(false); setTempName(doc.name); }} className="p-1 text-red-600 hover:bg-red-50 rounded">
                <CloseIcon size={16} />
              </button>
            </div>
          ) : (
            <div className="flex items-center justify-center gap-2 group">
              <h2 className="text-lg font-bold text-slate-900 break-words line-clamp-2">{doc.name}</h2>
              <button 
                onClick={() => setIsRenaming(true)}
                className="opacity-0 group-hover:opacity-100 p-1 text-slate-400 hover:text-blue-600 transition-all"
              >
                <Pencil size={14} />
              </button>
            </div>
          )}
          {doc.contractNumber && (
            <p className="text-xs font-bold text-blue-600 flex items-center justify-center gap-1">
              <Hash size={12} /> {doc.contractNumber}
            </p>
          )}
          <p className="text-sm text-slate-500 mt-1 uppercase tracking-wider font-semibold">{t(lang, 'version')} {doc.currentVersion}</p>
        </div>

        <div className="flex items-center justify-center gap-2 pt-2">
          <ActionButton icon={<Eye size={18} />} label="Preview" onClick={onPreview} />
          <ActionButton icon={<Printer size={18} />} label="Print" onClick={onPrint} />
          <ActionButton icon={<Download size={18} />} label={t(lang, 'download')} />
          <ActionButton icon={<Share2 size={18} />} label={t(lang, 'share')} />
          <ActionButton icon={<Trash2 size={18} />} label={t(lang, 'delete')} variant="danger" onClick={onTrash} />
        </div>
      </div>

      {/* Info Sections */}
      <div className="flex-1 overflow-y-auto p-6 space-y-8">
        <section className="space-y-4">
          <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
            <Info size={14} /> {t(lang, 'details')}
          </h3>
          <div className="grid grid-cols-2 gap-4">
            <InfoItem icon={<User size={14} />} label={lang === 'en' ? "Owner" : "ባለቤት"} value="System Admin" />
            <InfoItem icon={<Database size={14} />} label={t(lang, 'size')} value={doc.size} />
            <InfoItem icon={<Calendar size={14} />} label={t(lang, 'modified')} value={new Date(doc.lastModified).toLocaleDateString()} />
            <InfoItem icon={<Shield size={14} />} label={lang === 'en' ? "Security" : "ደህንነት"} value="AES-256" />
          </div>
        </section>

        <section className="space-y-4">
          <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
            <History size={14} /> {t(lang, 'history')}
          </h3>
          <div className="space-y-3">
            {doc.versions.map((v, idx) => (
              <div key={v.id} className={`p-3 rounded-xl border ${idx === 0 ? 'bg-blue-50 border-blue-100' : 'bg-white border-slate-100 hover:bg-slate-50'} transition-all group`}>
                <div className="flex items-center justify-between mb-1">
                  <span className="text-xs font-bold text-slate-800">v{v.versionNumber}</span>
                  <span className="text-[10px] text-slate-400 font-medium">{new Date(v.updatedAt).toLocaleDateString()}</span>
                </div>
                <p className="text-xs text-slate-600 line-clamp-1">{v.changeNote}</p>
              </div>
            ))}
          </div>
        </section>

        <section className="space-y-4 pb-8">
           <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest">{t(lang, 'tags')}</h3>
           <div className="flex flex-wrap gap-2">
              {doc.tags.map(tag => (
                <span key={tag} className="px-2 py-1 bg-slate-100 text-slate-600 rounded-lg text-xs font-medium border border-slate-200">#{tag}</span>
              ))}
              <button className="px-2 py-1 bg-white border border-dashed border-slate-300 text-slate-400 rounded-lg text-xs font-medium hover:border-blue-400 hover:text-blue-500 transition-all">+ {lang === 'en' ? 'Add' : 'አክል'}</button>
           </div>
        </section>
      </div>
    </div>
  );
};

const ActionButton = ({ icon, label, variant = 'default', onClick }: { icon: React.ReactNode, label: string, variant?: 'default' | 'danger', onClick?: () => void }) => (
  <button 
    onClick={onClick}
    className={`p-3 rounded-xl transition-all shadow-sm border ${
      variant === 'danger' 
      ? 'bg-red-50 border-red-100 text-red-600 hover:bg-red-100' 
      : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'
    }`}
    title={label}
  >
    {icon}
  </button>
);

const InfoItem = ({ icon, label, value }: { icon: React.ReactNode, label: string, value: string }) => (
  <div className="space-y-1">
    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider flex items-center gap-1">
      {icon} {label}
    </p>
    <p className="text-sm font-semibold text-slate-800">{value}</p>
  </div>
);

export default DocumentDetails;

import React, { useState, useEffect, useRef } from 'react';
import { 
  X, Download, Printer, Maximize2, FileText, ChevronLeft, ChevronRight, 
  ZoomIn, ZoomOut, Image as ImageIcon, BrainCircuit, Sparkles, Send, 
  RotateCcw, Info, PanelRightClose, PanelRightOpen, MessageSquare, Quote
} from 'lucide-react';
import { Document, FileType } from '../types';
import { getFileIcon } from '../constants';
import { Language, t } from '../translations';
import { askDocumentQuestion, summarizeDocument } from '../services/geminiService';

interface DocumentPreviewProps {
  doc: Document;
  onClose: () => void;
  lang: Language;
  autoPrint?: boolean;
}

const DocumentPreview: React.FC<DocumentPreviewProps> = ({ doc, onClose, lang, autoPrint = false }) => {
  const [zoom, setZoom] = useState(100);
  const [showAI, setShowAI] = useState(true);
  const [aiLoading, setAiLoading] = useState(false);
  const [summary, setSummary] = useState<string | null>(null);
  const [chatQuery, setChatQuery] = useState('');
  const [chatHistory, setChatHistory] = useState<{ role: 'user' | 'ai', content: string }[]>([]);
  const chatEndRef = useRef<HTMLDivElement>(null);

  const isImage = doc.type === FileType.IMG;
  const imageUrl = doc.previewUrl || doc.previewContent;

  const handleZoomIn = () => setZoom(prev => Math.min(prev + 25, 300));
  const handleZoomOut = () => setZoom(prev => Math.max(prev - 25, 25));

  const handlePrint = () => {
    window.print();
  };

  useEffect(() => {
    if (autoPrint) {
      // Small timeout to ensure the modal content is rendered before print dialog appears
      const timer = setTimeout(() => {
        window.print();
      }, 800);
      return () => clearTimeout(timer);
    }
  }, [autoPrint]);

  const scrollToBottom = () => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [chatHistory, aiLoading]);

  const handleSummarize = async () => {
    if (!doc.previewContent) return;
    setAiLoading(true);
    const result = await summarizeDocument(doc.previewContent);
    setSummary(result || "Could not generate summary.");
    setAiLoading(false);
  };

  const handleChat = async () => {
    if (!chatQuery.trim() || !doc.previewContent) return;
    const userMsg = chatQuery;
    setChatQuery('');
    setChatHistory(prev => [...prev, { role: 'user', content: userMsg }]);
    setAiLoading(true);

    const response = await askDocumentQuestion(doc.previewContent, userMsg);
    setChatHistory(prev => [...prev, { role: 'ai', content: response || "I'm sorry, I couldn't process that." }]);
    setAiLoading(false);
  };

  return (
    <div className="fixed inset-0 z-[100] flex flex-col bg-slate-900/95 backdrop-blur-md animate-in fade-in duration-300 overflow-hidden">
      <style>{`
        @media print {
          body * {
            visibility: hidden;
          }
          #print-area, #print-area * {
            visibility: visible;
          }
          #print-area {
            position: absolute;
            left: 0;
            top: 0;
            width: 100%;
            background: white !important;
            padding: 0 !important;
            margin: 0 !important;
          }
          #print-area > div {
            transform: none !important;
            width: 100% !important;
            max-width: 100% !important;
            box-shadow: none !important;
            border: none !important;
            margin: 0 !important;
            padding: 1cm !important;
          }
          .no-print {
            display: none !important;
          }
          pre {
            white-space: pre-wrap !important;
            font-size: 11pt !important;
            color: black !important;
          }
        }
      `}</style>

      {/* Top Toolbar */}
      <header className="h-16 flex items-center justify-between px-6 bg-slate-900 border-b border-slate-800 shrink-0 z-20 no-print">
        <div className="flex items-center gap-4">
          <button 
            onClick={onClose}
            className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded-lg transition-all"
          >
            <X size={20} />
          </button>
          <div className="flex items-center gap-3">
            <div className="p-2 bg-slate-800 rounded-lg border border-slate-700">
              {getFileIcon(doc.type)}
            </div>
            <div>
              <h2 className="text-white font-bold text-sm leading-none mb-1">{doc.name}</h2>
              <p className="text-slate-500 text-[10px] uppercase font-bold tracking-widest">
                {t(lang, 'version')} {doc.currentVersion} • {doc.size}
              </p>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-2">
          <div className="flex items-center gap-1 bg-slate-800 p-1 rounded-xl border border-slate-700">
            <ToolbarButton icon={<ZoomOut size={16} />} label="Zoom Out" onClick={handleZoomOut} />
            <span className="text-slate-300 text-[10px] font-black w-10 text-center uppercase tracking-tighter">{zoom}%</span>
            <ToolbarButton icon={<ZoomIn size={16} />} label="Zoom In" onClick={handleZoomIn} />
          </div>
          <div className="w-px h-6 bg-slate-700 mx-2" />
          <ToolbarButton icon={<Printer size={18} />} label="Print" onClick={handlePrint} />
          <ToolbarButton icon={<Download size={18} />} label={t(lang, 'download')} />
          <button 
            onClick={() => setShowAI(!showAI)}
            className={`flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-bold transition-all shadow-lg ${
              showAI 
              ? 'bg-blue-600 text-white shadow-blue-900/20' 
              : 'bg-slate-800 text-slate-400 border border-slate-700 hover:text-white'
            }`}
