                  <p className="text-sm font-bold text-slate-800 truncate">{activeFolderName}</p>
                </div>
                <ChevronDown size={14} className={`text-slate-400 transition-transform ${kebeleDropdownOpen ? 'rotate-180' : ''}`} />
              </button>

              {kebeleDropdownOpen && (
